={{
(() => {
  const produkt = String($json.body.produkt || '').toLowerCase();
  const wariant = String($json.body.wariant_wyceny_wybrany || '').toLowerCase();
  const montazBez = String($json.body.montaz_bez_montazu || '').toUpperCase();

  const katalogBrutto = Number($json.body.cena_katalogowa_brutto || 0);
  const nettoProduktu = Number($json.body.cena_netto_produktu || 0);

  const czyDrzwi = produkt.includes('drzwi');

  if (czyDrzwi && katalogBrutto > 0) {
    if (montazBez === 'TAK') {
      return Math.round((katalogBrutto / 1.08) * 100) / 100;
    }

    if (wariant.includes('bez')) {
      return Math.round((katalogBrutto / 1.23) * 100) / 100;
    }

    if (wariant.includes('montaż') || wariant.includes('montaz')) {
      return Math.round((katalogBrutto / 1.08) * 100) / 100;
    }
  }

  return Math.round(nettoProduktu * 100) / 100;
})()
}}

