const item = $input.first().json;

const now = new Date();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0');
const day = String(now.getDate()).padStart(2, '0');
const timestamp = Date.now();

item.generated_id = `WYC-${year}${month}${day}-${timestamp}`;
item.data_utworzenia = now.toISOString();

return [{ json: item }];

const rows = $input.all().map(i => i.json);
const input = $('Normalizacja danych zamówienia').first().json;

const normalize = (v) =>
  String(v || '')
    .trim()
    .toLowerCase();

const normalizePhone = (v) =>
  String(v || '')
    .replace(/\s+/g, '')
    .replace(/[^0-9+]/g, '');

const surname = normalize(input.nazwisko);
const phone = normalizePhone(input.telefon);
const city = normalize(input.miasto);
const street = normalize(input.ulica_i_numer);

const matches = rows.filter(row => {
  const rowSurname = normalize(row['Nazwisko']);
  const rowPhone = normalizePhone(row['Telefon']);
  const rowCity = normalize(row['Miasto']);
  const rowStreet = normalize(row['Ulica']);

  // 1. najmocniejsze dopasowanie: telefon
  if (phone && rowPhone === phone) return true;

  // 2. drugie dopasowanie: nazwisko + miasto
  if (surname && city && rowSurname === surname && rowCity === city) return true;

  // 3. trzecie dopasowanie: nazwisko + ulica
  if (surname && street && rowSurname === surname && rowStreet === street) return true;

  // 4. awaryjnie samo nazwisko
  if (surname && rowSurname === surname) return true;

  return false;
});

if (matches.length === 0) {
  return [{
    json: {
      ok: false,
      message: 'Nie znaleziono pasującej wyceny.'
    }
  }];
}

if (matches.length > 1) {
  return [{
    json: {
      ok: false,
      message: 'Znaleziono więcej niż jedną wycenę. Doprecyzuj telefon klienta.'
    }
  }];
}

return [{
  json: matches[0]
}];

const payload = $('Normalizacja danych zamówienia').first().json; 

const rows = $input.all().map(i => i.json);

const normalizeText = (value) => String(value || '').trim().toLowerCase();
const normalizePhone = (value) =>
  String(value || '').replace(/\s+/g, '').replace(/-/g, '').trim();

const surname = normalizeText(payload.nazwisko);
const phone = normalizePhone(payload.telefon);
const city = normalizeText(payload.miasto);
const street = normalizeText(payload.ulica_i_numer);

const matches = rows.filter(row => {
  const rowSurname = normalizeText(row['Nazwisko']);
  const rowPhone = normalizePhone(row['Telefon']);
  const rowCity = normalizeText(row['Miasto']);
  const rowStreet = normalizeText(row['Ulica']);

  let ok = true;

  if (surname) ok = ok && rowSurname === surname;
  if (phone) ok = ok && rowPhone === phone;
  if (city) ok = ok && rowCity === city;
  if (street) ok = ok && rowStreet === street;

  return ok;
});



if (matches.length === 0) {
  return [{
    json: {
      match_count: 0,
      message: 'Nie znaleziono pasującej wyceny.'
    }
  }];
}

if (matches.length > 1) {
  return [{
    json: {
      match_count: matches.length,
      message: 'Znaleziono więcej niż jedną wycenę. Podaj telefon albo adres.'
    }
  }];
}

return [{
  json: {
    ...matches[0],
    match_count: 1
  }
}];

const quote = $input.first().json;
const payload = $('Normalizacja danych zamówienia').first().json;

// ---------------- HELPERY ----------------

const normalize = (v) =>
  String(v || '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ');

const toNumber = (v) => {
  const raw = String(v ?? '')
    .replace(',', '.')
    .replace(/[^\d.-]/g, '')
    .trim();

  const num = Number(raw);
  return Number.isFinite(num) ? num : 0;
};

const containsAny = (text, phrases) =>
  phrases.some(p => normalize(text).includes(normalize(p)));

const safe = (v) => String(v ?? '').trim();

const getFirstNumber = (...values) => {
  for (const v of values) {
    const n = toNumber(v);
    if (n !== 0) return n;
  }
  return 0;
};

const round2 = (n) => Math.round((n + Number.EPSILON) * 100) / 100;

// ---------------- DANE Z WYCENY ----------------

const grossWithInstallation = toNumber(quote['Cena brutto z montażem (8%)']);
const grossWithoutInstallation = toNumber(quote['Cena brutto bez montażu (23%)']);

const servicePriceFromQuote = toNumber(
  quote['Cena montażu'] ||
  quote['Cena montażu klient'] ||
  quote['cena_montazu'] ||
  quote['cena_montazu_klient']
);

const cenaWycenyFromQuote = toNumber(
  quote['Cena wyceny (kwota całkowita)'] ||
  quote['Cena wyceny'] ||
  quote['cena_wyceny']
);

const cenaProduktuKlientFromQuote = toNumber(
  quote['Cena produktu klient'] ||
  quote['cena_produktu_klient'] ||
  quote['Cena netto produktu']
);

const cenaKatalogowaBrutto = toNumber(
  quote['Cena katalogowa brutto'] ||
  quote['cena_katalogowa_brutto']
);

const cenaKatalogowaNetto = toNumber(
  quote['Cena katalogowa netto'] ||
  quote['cena_katalogowa_netto']
);

const vat = toNumber(
  quote['VAT'] ||
  quote['vat']
);

const cenaProduktuProducent = toNumber(
  quote['Cena produktu producent'] ||
  quote['cena_produktu_producent'] ||
  quote['Cena produktu producenta'] ||
  quote['Cena produktu pr'] ||
  quote['Cena produktu pr...']
);

const cenaMontazuEkipyFromQuote = toNumber(
  quote['Cena montażu ekipy'] ||
  quote['cena_montazu_ekipy']
);

const selectedVariantRaw = safe(
  quote['Wariant wyceny wybrany (z montażem / bez montażu)']
);

const selectedVariant = normalize(selectedVariantRaw);

const jednostka = safe(
  quote['Jednostka (mm/cm/m)'] ||
  quote['Jednostka']
);

const kierunekOtwierania = safe(
  payload.kierunek_otwierania ||
  quote['Kierunek otwierania'] ||
  quote['kierunek_otwierania'] ||
  ''
);

// ---------------- DOJAZD ----------------

const odlegloscKm = getFirstNumber(
  payload.odleglosc_km,
  payload['Odległość (km)'],
  quote.odleglosc_km,
  quote['Odległość (km)']
);

const kosztDojazdu = getFirstNumber(
  payload.koszt_dojazdu,
  payload['Koszt dojazdu'],
  quote.koszt_dojazdu,
  quote['Koszt dojazdu']
);

// ---------------- ROZPOZNANIE USŁUGI ----------------

const getTakNie = (...values) => {
  for (const value of values) {
    const v = String(value || '').trim().toUpperCase();
    if (v === 'TAK' || v === 'NIE') return v;
  }
  return '';
};

const directUsluga = getTakNie(
  payload.czy_usluga_montazu,
  payload.usluga_montazu,
  quote['Czy usługa montażu (TAK/NIE)'],
  quote['Usługa montażu']
);

const directMontaz = getTakNie(
  payload.czy_montaz,
  payload.montaz,
  quote['Czy montaż (TAK/NIE)'],
  quote['Montaż']
);

const directDemontaz = getTakNie(
  payload.czy_demontaz,
  payload.demontaz,
  quote['Czy demontaż (TAK/NIE)'],
  quote['Demontaż']
);

const directMontazBezMontazu = getTakNie(
  payload.montaz_bez_montazu,
  quote['Montaż bez montażu (TAK/NIE)'],
  quote['Montaż bez montażu / na VAT (TAK/NIE)']
);

const montazBezMontazu =
  directMontazBezMontazu
    ? directMontazBezMontazu === 'TAK'
    : containsAny(
        `${selectedVariantRaw} ${payload.uwagi || ''} ${payload.szczegoly || ''}`,
        [
          'montaż bez montażu',
          'montaz bez montazu',
          'z montażem ale bez montażu',
          'z montazem ale bez montazu',
          'montaż tylko na fakturze',
          'montaz tylko na fakturze',
          'na 8% vat bez montażu',
          'na 8% vat bez montazu'
        ]
      );

let hasMontaz =
  directMontaz
    ? directMontaz === 'TAK'
    : (
        containsAny(selectedVariant, [
          'z montazem',
          'z montazem i demontazem',
          'z montazem bez demontazu',
          'sam montaz'
        ]) &&
        !containsAny(selectedVariant, [
          'bez montazu',
          'montaz bez montazu'
        ])
      );

let hasDemontaz =
  directDemontaz
    ? directDemontaz === 'TAK'
    : (
        containsAny(selectedVariant, [
          'z montazem i demontazem',
          'bez montazu z demontazem',
          'sam demontaz',
          'demontaz'
        ]) &&
        !containsAny(selectedVariant, ['bez demontazu'])
      );

if (montazBezMontazu) {
  hasMontaz = false;
  hasDemontaz = false;
}

let hasUslugaMontazu =
  directUsluga
    ? directUsluga === 'TAK'
    : hasMontaz || hasDemontaz || montazBezMontazu;

const hasOnlyNoServices =
  !hasUslugaMontazu && !hasMontaz && !hasDemontaz && !montazBezMontazu;

// ---------------- KWOTA CAŁKOWITA ----------------

let total = cenaWycenyFromQuote;

if (!total) {
  if (hasUslugaMontazu || montazBezMontazu) {
    total = grossWithInstallation || grossWithoutInstallation || 0;
  } else {
    total = grossWithoutInstallation || grossWithInstallation || 0;
  }
}

// ---------------- CENA MONTAŻU ----------------

let cenaMontazuKlient = 0;

if (montazBezMontazu) {
  cenaMontazuKlient = servicePriceFromQuote;
} else if (hasOnlyNoServices) {
  cenaMontazuKlient = 0;
} else if (hasUslugaMontazu) {
  cenaMontazuKlient = servicePriceFromQuote;
}

const cenaMontazuEkipyFinal = montazBezMontazu
  ? 0
  : cenaMontazuEkipyFromQuote;

// ---------------- ZAROBEK ----------------

const zarobekProdukt = round2(cenaProduktuKlientFromQuote - cenaProduktuProducent);
const zarobekMontaz = round2(cenaMontazuKlient - cenaMontazuEkipyFinal);
const zarobekCalosc = round2(zarobekProdukt + zarobekMontaz);

// ---------------- ZALICZKA ---------------

const ZALICZKA_PROCENT = 0.30;

const zaliczkaZPayload =
  payload.kwota_zaliczki !== "" &&
  payload.kwota_zaliczki !== null &&
  payload.kwota_zaliczki !== undefined
    ? toNumber(payload.kwota_zaliczki)
    : 0;

const zaliczkaZWyceny = toNumber(
  quote['Zaliczka (30%)'] ||
  quote['Zaliczka'] ||
  quote['zaliczka_30'] ||
  quote['zaliczka']
);

let deposit = 0;

// Jeśli właściciel podał konkretną zaliczkę przy przenoszeniu — użyj jej
if (zaliczkaZPayload > 0) {
  deposit = zaliczkaZPayload;
}
// Jeśli w wycenie jest już zapisana zaliczka — przenieś ją
else if (zaliczkaZWyceny > 0) {
  deposit = zaliczkaZWyceny;
}
// Jeśli nie ma żadnej zaliczki — policz automatycznie
else {
  deposit = Math.floor((total * ZALICZKA_PROCENT) / 100) * 100;
}
const remaining = round2(total - deposit);

// ---------------- DATY / ID ----------------

const today = new Intl.DateTimeFormat('en-CA', {
  timeZone: 'Europe/Warsaw'
}).format(new Date());

const orderId = 'ZAM-' + Date.now();

// ---------------- FORMA PŁATNOŚCI ----------------

let paymentMethod = normalize(payload.metoda_platnosci || '');

if (paymentMethod === 'gotowka') paymentMethod = 'gotówka';
if (paymentMethod === 'gotówką') paymentMethod = 'gotówka';
if (paymentMethod === 'przelewem') paymentMethod = 'przelew';
if (paymentMethod === 'przelew bankowy') paymentMethod = 'przelew';

// ---------------- ZWROT ----------------

return [
  {
    json: {
      id_wyceny: quote['ID (unikalny numer)'] || "",
      imie: payload.imie || quote['Imię'] || "",
      nazwisko: payload.nazwisko || quote['Nazwisko'] || "",
      telefon: payload.telefon || quote['Telefon'] || "",
      email: quote['Email'] || "",
      ulica: payload.ulica_i_numer || quote['Ulica'] || "",
      miasto: payload.miasto || quote['Miasto'] || "",
      kod_pocztowy: quote['Kod pocztowy'] || "",

      typ_klienta:
        quote[' Typ klienta (prywatny / firma)'] ||
        quote['Typ klienta (prywatny / firma)'] ||
        "prywatny",

      produkty: quote['Produkt'] || "",
      zrodlo: quote['Źródło (mail / telefon / inne)'] || "inne",
      model: quote['Model'] || "",
      kolor: quote['Kolor'] || "",
      kierunek_otwierania: kierunekOtwierania,
      wymiary: quote['Wymiary'] || "",
      jednostka: jednostka,
      ilosc: quote['Ilość'] || "",

      usluga_montazu: hasUslugaMontazu ? 'TAK' : 'NIE',
      montaz: hasMontaz ? 'TAK' : 'NIE',
      demontaz: hasDemontaz ? 'TAK' : 'NIE',
      montaz_bez_montazu: montazBezMontazu ? 'TAK' : 'NIE',

      wariant_wyceny_wybrany: selectedVariantRaw,
      status: 'do zamówienia',

      data_zaliczki: payload.data_zaliczki || today,
      data_pomiaru: payload.data_pomiaru || "",
      data_montazu: payload.data_montazu || "",
      data_utworzenia_zamowienia: today,

      kwota_calkowita: total,
      cena_wyceny: total,
      zaliczka: deposit,
      pozostalo_do_zaplaty: remaining,

      forma_platnosci: paymentMethod || "",
      status_platnosci: deposit > 0 ? "częściowo opłacone" : "nieopłacone",

      id_zamowienia_fakturownia: "",
      id_faktury_zaliczkowej: "",
      id_faktury_koncowej: "",
      id_faktury_zwyklej: "",
      id_zamowienia_wewnetrznego: orderId,

      numer_faktury_zaliczkowej: "",
      numer_faktury_koncowej: "",
      numer_faktury_zwyklej: "",
      numer_umowy: "",
      numer_protokolu: "",
      numer_zlecenia: "",

      cena_katalogowa_brutto: cenaKatalogowaBrutto,
      cena_katalogowa_netto: cenaKatalogowaNetto,
      vat: vat,
      cena_produktu_klient: cenaProduktuKlientFromQuote,
      cena_produktu_producent: cenaProduktuProducent,
      cena_montazu_klient: cenaMontazuKlient,
      cena_montazu_ekipy: cenaMontazuEkipyFinal,

      koszt_dojazdu: kosztDojazdu,
      odleglosc_km: odlegloscKm,
      'Koszt dojazdu': kosztDojazdu,
      'Odległość (km)': odlegloscKm,

      zarobek_produkt: zarobekProdukt,
      zarobek_montaz: zarobekMontaz,
      zarobek_calosc: zarobekCalosc,

      numer_WEB: "",
      numer_Kosztorys_WEB: "",
      plik_WEB_link: "",
      plik_Kosztorys_WEB_link: "",

      przyszlo: "NIE",
      data_przyjscia_towaru: "",
      czy_zamowione_u_producenta: "NIE",

      producent: "",
      data_wyslania_zamowienia: "",
      sposob_zamowienia: "",
      status_zamowienia_producenta: "",

      etap_6_wykonany: "NIE",
      data_wykonania_etapu_6: "",

      pozycja_zamowiona_automatycznie: "NIE",
      pozycja_wymaga_recznego_zamowienia: "TAK",

      czy_zamowienie_w_fakturowni_utworzone: "NIE",
      czy_faktura_zaliczkowa_wystawiona: "NIE",
      czy_mail_do_producenta_wyslany: "NIE",
      faktura_koncowa_wystawiona: "NIE",

      czy_umowa_wygenerowana: "NIE",
      czy_zlecenie_wygenerowane: "NIE",
      czy_protokol_wygenerowany: "NIE",
      czy_montaz_wykonany: "NIE",

      data_sms_montaz_klient: "",
      data_sms_montaz_ekipa: "",
      data_sms_odbior_towaru: "",

      czy_pomiar_dodany_do_kalendarza: "NIE",
      czy_montaz_dodany_do_kalendarza: "NIE",

      uwagi_do_faktury_zaliczkowej: "",
      uwagi_do_faktury_koncowej: "",
      uwagi_wewnetrzne_montaz_vat: montazBezMontazu
        ? "Montaż bez montażu — usługa na fakturze, bez fizycznego montażu."
        : "",

      uwagi:
        payload.uwagi ||
        quote['Uwagi'] ||
        quote['uwagi'] ||
        "",

      szczegoly:
        payload.szczegoly ||
        quote['Szczegóły'] ||
        quote['Szczegoly'] ||
        quote['szczegoly'] ||
        "",

      link_do_folderu_klienta: "",

      debug_wariant_uslugi: {
        selectedVariantRaw,
        hasUslugaMontazu,
        hasMontaz,
        hasDemontaz,
        hasOnlyNoServices,
        montazBezMontazu,
        directUsluga,
        directMontaz,
        directDemontaz,
        directMontazBezMontazu,
        servicePriceFromQuote,
        grossWithInstallation,
        grossWithoutInstallation,
        total,
        cenaKatalogowaBrutto,
        cenaKatalogowaNetto,
        vat,
        cenaProduktuKlientFromQuote,
        cenaProduktuProducent,
        cenaMontazuKlient,
        cenaMontazuEkipyFinal,
        zarobekProdukt,
        zarobekMontaz,
        zarobekCalosc,
        odlegloscKm,
        kosztDojazdu
      }
    }
  }
];

const rows = $input.all().map(i => i.json);
const inputData = $('Mapowanie danych wejściowych').first().json;

const normalize = (v) =>
  String(v || '')
    .trim()
    .toLowerCase();

const normalizePhone = (v) =>
  String(v || '')
    .replace(/\s+/g, '')
    .replace(/[^0-9+]/g, '');

const surname = normalize(inputData.nazwisko);
const phone = normalizePhone(inputData.telefon);

if (!surname && !phone) {
  return [{
    json: {
      ok: false,
      message: 'Podaj nazwisko albo telefon klienta.'
    }
  }];
}

const matches = rows.filter(row => {
  const rowSurname = normalize(row['Nazwisko']);
  const rowPhone = normalizePhone(row['Telefon']);

  let ok = true;

  if (surname) ok = ok && rowSurname === surname;
  if (phone) ok = ok && rowPhone === phone;

  return ok;
});

if (matches.length === 0) {
  return [{
    json: {
      ok: false,
      message: 'Nie znaleziono zamówienia.'
    }
  }];
}

if (matches.length > 1) {
  return [{
    json: {
      ok: false,
      message: 'Znaleziono więcej niż jedno zamówienie. Podaj telefon klienta.'
    }
  }];
}

return [{
  json: {
    ok: true,
    ...matches[0]
  }
}];

const row = $input.first().json;
const link = String(row['Link do folderu klienta'] || '').trim();
const match = link.match(/\/folders\/([a-zA-Z0-9\-_]+)/);

if (!match) {
  return [{
    json: {
      ...row,
      ok: false,
      message: 'Brak poprawnego linku do folderu klienta.'
    }
  }];
}

return [{
  json: {
    ...row,
    ok: true,
    folder_client_id: match[1]
  }
}];

const rows = $input.all().map(i => i.json);

const year = String(new Date().getFullYear());

const getField = (obj, wantedName) => {
  const key = Object.keys(obj).find(
    k => String(k).trim().toLowerCase() === wantedName.trim().toLowerCase()
  );
  return key ? obj[key] : undefined;
};

const normalize = (v) =>
  String(v ?? '')
    .trim()
    .toUpperCase();

const debugRows = rows.map(r => ({
  keys: Object.keys(r),
  typ: getField(r, 'Typ dokumentu'),
  rok: getField(r, 'Rok'),
  ostatni: getField(r, 'Ostatni numer'),
  row_number: getField(r, 'row_number')
}));

const match = rows.find(r => {
  const typ = normalize(getField(r, 'Typ dokumentu'));
  const rok = String(getField(r, 'Rok') ?? '').trim();

  return typ === 'UMOWA' && rok === year;
});

if (!match) {
  return [{
    json: {
      ok: false,
      message: `Brak numeracji dla UMOWA / ${year}`,
      debug_year: year,
      debug_rows: debugRows
    }
  }];
}

const rowNumber = getField(match, 'row_number');
const lastNumber = Number(getField(match, 'Ostatni numer') || 0);
const nextNumber = lastNumber + 1;
const padded = String(nextNumber).padStart(3, '0');
const numer_umowy = `UM/${year}/${padded}`;

return [{
  json: {
    ok: true,
    row_number: rowNumber,
    last_number: lastNumber,
    next_number: nextNumber,
    numer_umowy
  }
}];

const order = $('Pobieranie ID folderu klienta').first().json;
const numbering = $('Wyliczenie numeru umowy').first().json;
const config = $('Konfiguracja generowania umowy').first().json;

const today = new Date().toLocaleDateString('pl-PL', {
  timeZone: 'Europe/Warsaw'
});

const safe = (v) => String(v ?? '').trim();

const normalize = (v) =>
  safe(v)
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');

const isTak = (v) => ['tak', 'true', '1', 'yes'].includes(normalize(v));

const getField = (...values) => {
  for (const v of values) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
};

const buildUslugaMontazuOpis = (row) => {
  const uslugaMontazu = getField(
    row['Czy usługa montażu (TAK/NIE)'],
    row['czy_usluga_montazu'],
    row['Usługa montażu'],
    row['Usluga montazu'],
    row['usluga_montazu']
  );

  const montaz = getField(
    row['Czy montaż (TAK/NIE)'],
    row['czy_montaz'],
    row['Montaż'],
    row['Montaz'],
    row['montaz']
  );

  const demontaz = getField(
    row['Czy demontaż (TAK/NIE)'],
    row['czy_demontaz'],
    row['Demontaż'],
    row['Demontaz'],
    row['demontaz']
  );

  const montazBezMontazu = getField(
    row['Montaż bez montażu (TAK/NIE)'],
    row['montaz_bez_montazu']
  );

  const uslugaTak = isTak(uslugaMontazu);
  const montazTak = isTak(montaz);
  const demontazTak = isTak(demontaz);
  const montazBezMontazuTak = isTak(montazBezMontazu);

  // Specjalny case wewnętrzny:
  // w arkuszu: montaż fizyczny NIE
  // w dokumencie dla klienta: normalnie usługa montażu
  if (montazBezMontazuTak) {
    return 'usługa montażu';
  }

  // Normalny montaż + demontaż
  if (uslugaTak && montazTak && demontazTak) {
    return 'usługa montażu: montaż i demontaż';
  }

  // Montaż bez demontażu
  if (uslugaTak && montazTak && !demontazTak) {
    return 'usługa montażu: montaż';
  }

  // Sam demontaż — nie nazywamy tego usługą montażu
  if (!montazTak && demontazTak) {
    return 'demontaż';
  }

  // Usługa montażu TAK, ale bez szczegółów
  if (uslugaTak) {
    return 'usługa montażu';
  }

  return 'brak usługi montażu';
};

const imie = safe(order['Imię']);
const nazwisko = safe(order['Nazwisko']);
const telefon = safe(order['Telefon']);
const email = safe(order['Email']);
const ulica = safe(order['Ulica']);
