      '{{NUMER_UMOWY}}': numbering.numer_umowy,
      '{{DATA_UMOWY}}': today,
      '{{ZAKRES_UMOWY}}': zakresUmowy,
      '{{IMIE}}': imie,
      '{{NAZWISKO}}': nazwisko,
      '{{ULICA}}': ulica,
      '{{MIASTO}}': miasto,
      '{{KOD_POCZTOWY}}': kod_pocztowy,
      '{{TELEFON}}': telefon,
      '{{EMAIL}}': email,
      '{{PRODUKT}}': produkt,
      '{{MODEL}}': model,
      '{{KOLOR}}': kolor,
      '{{ILOSC}}': ilosc,
      '{{WYMIARY}}': wymiary_z_jednostka,
      '{{MONTAZ}}': usluga_montazu_opis,
      '{{KWOTA_CALKOWITA}}': kwota_calkowita,
      '{{CZAS_REALIZACJI}}': czas_realizacji
    },
    debug_umowa_montaz: {
      usluga_montazu_opis,
      czy_usluga_montazu: getField(
        order['Czy usługa montażu (TAK/NIE)'],
        order['czy_usluga_montazu'],
        order['Usługa montażu'],
        order['usluga_montazu']
      ),
      czy_montaz: getField(
        order['Czy montaż (TAK/NIE)'],
        order['czy_montaz'],
        order['Montaż'],
        order['montaz']
      ),
      czy_demontaz: getField(
        order['Czy demontaż (TAK/NIE)'],
        order['czy_demontaz'],
        order['Demontaż'],
        order['demontaz']
      ),
      montaz_bez_montazu: getField(
        order['Montaż bez montażu (TAK/NIE)'],
        order['montaz_bez_montazu']
      )
    }
  }
}];

