const config = $('Konfiguracja generowania zlecenia1').first().json;

const safe = (v) => String(v ?? '').trim();

const normalize = (v) =>
  safe(v)
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');

const normalizeEmptyText = (v) => {
  const raw = safe(v);
  const n = normalize(raw);

  if (
    !raw ||
    n === 'brak dodatkowych informacji' ||
    n === 'brak informacji' ||
    n === 'brak uwag' ||
    n === 'bez uwag' ||
    n === 'brak' ||
    n === '-' ||
    n === 'none'
  ) {
    return '';
  }

  return raw;
};

const imie = safe(order['Imię']);
const nazwisko = safe(order['Nazwisko']);
const ulica = safe(order['Ulica']);
const miasto = safe(order['Miasto']);
const kod_pocztowy = safe(order['Kod pocztowy']);

const produkt = safe(order['Produkty (opis)'] || order['Produkt']);
const model = safe(order['Model']);
const kolor = safe(order['Kolor']);
const ilosc = safe(order['Ilość'] || order['ilosc']);

const wymiarValue = safe(order['Wymiary']);
const jednostka = safe(order['Jednostka (mm/cm/m)'] || order['Jednostka']);
const wymiary = [wymiarValue, jednostka].filter(Boolean).join(' ');

const data_utworzenia = safe(order['Data utworzenia zamówienia']);
const data_montazu = safe(order['Data montażu']);

