  order['Dodatkowe info'] ||
  order['Dodatkowe info '] ||
  order['dodatkowe_info']
);

const numer_zlecenia = safe(numbering.numer_dokumentu);

const productText = normalize(produkt);
const modelText = normalize(model);

let daysToFinish = 30;

if (
  productText.includes('drzwi zewnetrzne konfigurator') ||
  (productText.includes('drzwi zewnetrzne') && modelText.includes('konfigurator'))
) {
  daysToFinish = 60;
} else if (productText.includes('drzwi wewnetrzne') || productText.includes('drzwi wew')) {
  daysToFinish = 60;
} else if (productText.includes('bram')) {
  daysToFinish = 60;
}

const addDays = (dateString, days) => {
  if (!dateString) return '';
  const date = new Date(dateString);
  if (isNaN(date.getTime())) return '';
  date.setDate(date.getDate() + days);
  return date.toISOString().slice(0, 10);
};

const data_zakonczenia = addDays(data_montazu, daysToFinish);

const nazwaProduktu =
  model && produkt
    ? `${model} (${produkt})`
    : model || produkt;

const produktZlecenie = [
  nazwaProduktu,
  kolor ? `kolor: ${kolor}` : '',
  ilosc ? `ilość: ${ilosc}` : '',
  wymiary ? `wymiar: ${wymiary}` : ''
].filter(Boolean).join(', ');

const zakresPrac = `zakup i montaż: ${produktZlecenie}`;

const wynagrodzenieNetto = Number(
  String(order['Cena montażu ekipy'] ?? '')
    .replace(',', '.')
    .replace(/[^\d.-]/g, '')
) || 0;

const wynagrodzenieBrutto = Math.round(wynagrodzenieNetto * 1.08 * 100) / 100;

const wynagrodzenieTekst = wynagrodzenieBrutto > 0
  ? `${wynagrodzenieBrutto} zł brutto`
  : '';

const infoDoZlecenia = dodatkowe_info || '';

const document_name = `Zlecenie ${numer_zlecenia} - ${nazwisko} ${imie}`;

return [{
  json: {
    template_zlecenie_id: config.template_zlecenie_id,
    folder_zlecenia_global_id: config.folder_zlecenia_global_id,
    folder_client_id: order.folder_client_id,
