      '{{MONTAZ}}': '',
      '{{DATA_MONTAZU}}': data_montazu,
      '{{DATA_ZAKONCZENIA}}': data_zakonczenia,

      '{{WYNAGRODZENIE_BRUTTO}}': wynagrodzenieTekst,
      '{{CENA_MONTAZU_EKIPY}}': wynagrodzenieTekst,

      '{{UWAGI}}': uwagi,
      '{{DODATKOWE_INFO}}': infoDoZlecenia,
      '{{INFO_DO_ZLECENIA}}': infoDoZlecenia
    },
    debug_zlecenie: {
      zakresPrac,
      wynagrodzenieNetto,
      wynagrodzenieBrutto,
      wynagrodzenieTekst,
      dodatkowe_info,
      infoDoZlecenia
    }
  }
}];

