const docCopy = $('Stworzenie kopii szablonu zlecenia1').first().json;
const prepared = $('Przygotowanie danych do dokumentu Google4').first().json;

const placeholders = prepared.placeholders || {};

const requests = Object.entries(placeholders)
  .filter(([key, value]) => key && value !== undefined && value !== null)
  .map(([key, value]) => ({
    replaceAllText: {
      containsText: {
        text: key,
        matchCase: true
      },
      replaceText: String(value)
    }
  }));

return [
  {
    json: {
      ...docCopy,
      requests
    }
  }
];

const rows = $input.all().map(i => i.json);
const config = $('Konfiguracja generowania zlecenia1').first().json;

const removeDiacritics = (value) =>
  String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');

const normalize = (value) =>
  removeDiacritics(value)
    .trim()
    .toUpperCase();

const getField = (obj, wantedName) => {
  const wanted = normalize(wantedName);
  const key = Object.keys(obj).find(k => normalize(k) === wanted);
  return key ? obj[key] : undefined;
};

const typDokumentu = normalize(config.typ_dokumentu || 'ZLECENIE');
const year = String(new Date().getFullYear()).trim();

const match = rows.find(r => {
  const typ = normalize(getField(r, 'Typ dokumentu'));
  const rok = String(getField(r, 'Rok') || '').trim();
  return typ === typDokumentu && rok === year;
});

if (!match) {
  return [{
    json: {
      ok: false,
      message: `Brak numeracji dla ${config.typ_dokumentu || 'ZLECENIE'} w roku ${year}`
    }
  }];
}

const lastNumber = Number(getField(match, 'Ostatni numer') || 0);
const newNumber = lastNumber + 1;

const prefixMap = {
  UMOWA: 'UM',
  PROTOKOL: 'PR',
  ZLECENIE: 'ZL'
};

const prefix = prefixMap[typDokumentu] || typDokumentu;
const numerDokumentu = `${prefix}/${year}/${String(newNumber).padStart(3, '0')}`;

return [{
  json: {
    ...config,
    ok: true,
    row_number: match.row_number,
    numer_dokumentu: numerDokumentu,
    nowy_numer: newNumber,
    typ_dokumentu: config.typ_dokumentu || 'ZLECENIE'
  }
}];

const rows = $input.all().map(i => i.json);
const inputData = $('Mapowanie danych wejściowych4').first().json;

const normalize = (v) =>
  String(v || '')
    .trim()
    .toLowerCase();

const normalizePhone = (v) =>
  String(v || '')
    .replace(/\s+/g, '')
    .replace(/[^0-9+]/g, '');

const surname = normalize(inputData.nazwisko);
const phone = normalizePhone(inputData.telefon);
const newInfo = String(inputData.uwagi || '').trim();

if (!surname && !phone) {
  return [{
    json: {
      ok: false,
      message: 'Podaj nazwisko albo telefon klienta.'
    }
  }];
}

if (!newInfo) {
  return [{
    json: {
      ok: false,
      message: 'Brakuje treści do zapisania w polu Uwagi.'
    }
  }];
}

const matches = rows.filter(row => {
  const rowSurname = normalize(row['Nazwisko']);
  const rowPhone = normalizePhone(row['Telefon']);

  let ok = true;

  if (surname) ok = ok && rowSurname === surname;
  if (phone) ok = ok && rowPhone === phone;

  return ok;
});

if (matches.length === 0) {
  return [{
    json: {
      ok: false,
      message: 'Nie znaleziono zamówienia.'
    }
  }];
}

if (matches.length > 1) {
  return [{
    json: {
      ok: false,
      message: 'Znaleziono więcej niż jedno zamówienie. Podaj telefon klienta.'
    }
  }];
}

return [{
  json: {
    ok: true,
    ...matches[0],
    nowe_uwagi: newInfo
  }
}];

const row = $input.first().json;

const existingInfo = String(
  row['Uwagi'] ||
  row['uwagi'] ||
  ''
).trim();

const newInfo = String(row.nowe_uwagi || '').trim();

let finalInfo = '';

if (existingInfo && newInfo) {
  finalInfo = `${existingInfo} | ${newInfo}`;
} else {
  finalInfo = existingInfo || newInfo || '';
}

return [{
  json: {
    ...row,
    final_uwagi: finalInfo
  }
}];

const rows = $input.all().map(i => i.json);
