parameters.jsCode:
const order = $('Budowa danych zamówienia').first().json;
const rows = $input.all().map(i => i.json);

// ---------------- HELPERY ----------------

const normalize = (v) =>
  String(v || '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ');

const toNumber = (v) => {
  const raw = String(v ?? '')
    .replace(',', '.')
    .replace(/[^\d.-]/g, '')
    .trim();

  const num = Number(raw);
  return Number.isFinite(num) ? num : 0;
};

const round2 = (n) => Math.round((n + Number.EPSILON) * 100) / 100;

const getField = (...values) => {
  for (const v of values) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
};

const extractFirstNumber = (value) => {
  const text = String(value || '').replace(',', '.');
  const match = text.match(/(\d+(\.\d+)?)/);
  return match ? Number(match[1]) : 0;
};

const detectUnitFromText = (value, fallbackUnit = '') => {
  const text = normalize(value);
  if (text.includes(' mm')) return 'mm';
  if (text.includes(' cm')) return 'cm';
  if (text.includes(' m')) return 'm';
  return normalize(fallbackUnit || '');
};

const containsAny = (text, phrases) =>
  phrases.some(p => normalize(text).includes(normalize(p)));

const toMeters = (value, unit) => {
  if (!value) return 0;
  if (unit === 'mm') return value / 1000;
  if (unit === 'cm') return value / 100;
  if (unit === 'm') return value;
  return value / 100;
};

const getPrice = (category, ...phrases) => {
  const cat = normalize(category);

  const row = rows.find(r => {
    const rowCategory = normalize(r['kategoria']);
    const rowOpis = normalize(r['opis']);

    if (rowCategory !== cat) return false;
    return phrases.some(phrase => rowOpis.includes(normalize(phrase)));
  });

  return row ? toNumber(row['cena']) : 0;
};

const getFirstNumber = (...values) => {
  for (const v of values) {
    const n = toNumber(v);
    if (n !== 0) return n;
  }
  return 0;
};

// ---------------- DOJAZD ----------------
// Dojazd NIE jest kosztem ekipy. Tylko przenosimy dalej.

const kosztDojazdu = getFirstNumber(
  order.koszt_dojazdu,
  order['Koszt dojazdu']
);

const odlegloscKm = getFirstNumber(
  order.odleglosc_km,
  order['Odległość (km)']
);

// ---------------- DANE ----------------

const produktRaw = getField(
  order.produkty,
  order.produkt,
  order['Produkty (opis)'],
  order['Produkt']
);

const modelRaw = getField(order.model, order['Model']);
const uwagiRaw = getField(order.uwagi, order['Uwagi']);
const szczegolyRaw = getField(order.szczegoly, order['Szczegóły'], order['Szczegoly']);

const wariantRaw = getField(
  order.wariant_wyceny_wybrany,
  order['Wariant wyceny wybrany (z montażem / bez montażu)']
);

const wymiarRaw = getField(order.wymiary, order['Wymiary']);

const jednostkaRaw = getField(
  order.jednostka,
  order['Jednostka'],
  order['Jednostka (mm/cm/m)']
);

const produkt = normalize(produktRaw);
const model = normalize(modelRaw);
const uwagi = normalize(uwagiRaw);
const szczegoly = normalize(szczegolyRaw);
const wariant = normalize(wariantRaw);

const wymiar = extractFirstNumber(wymiarRaw);
const jednostka = detectUnitFromText(wymiarRaw, jednostkaRaw);

const fullText = [produkt, model, uwagi, szczegoly, wariant].filter(Boolean).join(' | ');

// ---------------- FLAGI TECHNICZNE ----------------

const uslugaMontazuTak =
  normalize(
    order.czy_usluga_montazu ||
    order.usluga_montazu ||
    order['Czy usługa montażu (TAK/NIE)'] ||
    order['Usługa montażu']
  ) === 'tak';

const montazTak =
  normalize(
    order.czy_montaz ||
    order.montaz ||
    order['Czy montaż (TAK/NIE)'] ||
    order['Czy montaż fizyczny (TAK/NIE)'] ||
    order['Montaż']
  ) === 'tak';

const demontazTak =
  normalize(
    order.czy_demontaz ||
    order.demontaz ||
    order['Czy demontaż (TAK/NIE)'] ||
    order['Czy demontaż fizyczny (TAK/NIE)'] ||
    order['Demontaż']
  ) === 'tak';

const montazBezMontazuTak =
  normalize(
    order.montaz_bez_montazu ||
    order['Montaż bez montażu (TAK/NIE)'] ||
    order['Montaż bez montażu / na VAT (TAK/NIE)']
  ) === 'tak';

const hasOption = (...phrases) => containsAny(fullText, phrases);

// ---------------- MAPOWANIE KATEGORII ----------------

let category = '';

if (containsAny(produkt, ['okna', 'okno'])) {
  category = 'okna';
} else if (containsAny(produkt, ['drzwi zewnetrzne konfigurator', 'drzwi zew konfigurator'])) {
  category = 'drzwi_zew';
} else if (containsAny(produkt, ['drzwi zewnetrzne', 'drzwi zew'])) {
  category = 'drzwi_zew';
} else if (containsAny(produkt, ['drzwi wewnetrzne', 'drzwi wew'])) {
  category = 'drzwi_wew';
} else if (containsAny(produkt, ['drzwi'])) {
  category = 'drzwi_wew';
} else if (containsAny(produkt, ['parapety zewnetrzne', 'parapet zewnetrzny', 'parapet zewn', 'parapety zewn'])) {
  category = 'parapety_zewn';
} else if (containsAny(produkt, ['parapety wewnetrzne', 'parapet wewnetrzny', 'parapet wewn', 'parapety wewn'])) {
  category = 'parapety_wewn';
} else if (containsAny(produkt, ['parapet'])) {
  category = 'parapety_wewn';
} else if (containsAny(produkt, ['bramy', 'brama'])) {
  category = 'bramy';
} else if (containsAny(produkt, ['rolety', 'roleta', 'zaluzje', 'żaluzje', 'moskitiery', 'moskitiera'])) {
  category = 'rolety_zaluzje';
}

// ---------------- LICZENIE EKIPY ----------------

let cenaEkipy = 0;
const rozpiskaEkipy = [];

const addKoszt = (nazwa, kwota) => {
  const value = round2(toNumber(kwota));
  if (value > 0) {
    cenaEkipy = round2(cenaEkipy + value);
    rozpiskaEkipy.push(`${nazwa}: ${value} zł`);
  }
};

const debug = {
  category,
  produkt: produktRaw,
  model: modelRaw,
  wariant: wariantRaw,
  uwagi: uwagiRaw,
  szczegoly: szczegolyRaw,
  wymiar_raw: wymiarRaw,
  wymiar_first_number: wymiar,
  jednostka_detected: jednostka,
  uslugaMontazuTak,
  montazTak,
  demontazTak,
  montazBezMontazuTak,
  kosztDojazdu,
  odlegloscKm
};

const finish = (reason = '') => {
  cenaEkipy = round2(cenaEkipy);

  const rozpiskaKosztowEkipy = rozpiskaEkipy.length
    ? `${rozpiskaEkipy.join(' | ')} | Razem ekipa: ${cenaEkipy} zł`
    : reason || 'Brak kosztów ekipy';

  const cenaProduktuKlient = toNumber(order.cena_produktu_klient || order['Cena produktu klient']);
  const cenaProduktuProducent = toNumber(order.cena_produktu_producent || order['Cena produktu producent']);
  const cenaMontazuKlient = toNumber(
    order.cena_montazu_klient ||
    order.cena_montazu ||
    order['Cena montażu klient'] ||
    order['Cena montażu']
  );

  const zarobekProdukt = round2(cenaProduktuKlient - cenaProduktuProducent);
  const zarobekMontaz = round2(cenaMontazuKlient - cenaEkipy);
  const zarobekCalosc = round2(zarobekProdukt + zarobekMontaz);

  return [{
    json: {
      ...order,

      koszt_dojazdu: kosztDojazdu,
      odleglosc_km: odlegloscKm,
      'Koszt dojazdu': kosztDojazdu,
      'Odległość (km)': odlegloscKm,

      detected_category: category,

      cena_montazu_ekipy: cenaEkipy,
      rozpiska_kosztow_ekipy: rozpiskaKosztowEkipy,

      zarobek_produkt: zarobekProdukt,
      zarobek_montaz: zarobekMontaz,
      zarobek_calosc: zarobekCalosc,

      debug_cena_ekipy: {
        ...debug,
        reason,
        cenaProduktuKlient,
        cenaProduktuProducent,
        cenaMontazuKlient,
        cenaEkipy,
        zarobekProdukt,
        zarobekMontaz,
        zarobekCalosc
      }
    }
  }];
};

// Brak usługi albo montaż bez montażu = 0 kosztów ekipy
if (!uslugaMontazuTak || montazBezMontazuTak) {
  return finish(
    montazBezMontazuTak
      ? 'Montaż bez montażu — brak kosztów ekipy'
      : 'Brak usługi montażu / demontażu'
  );
}

// ---------------- OKNA ----------------

if (category === 'okna') {
  const mbObwodu = toMeters(wymiar, jednostka) * 4;
  const montaz = getPrice('okna', 'montaz okien piana kotwy', 'montaz');
  const szczelny = getPrice('okna', 'szczelny montaz jedna strona', 'szczelny montaz');
  const demontaz = getPrice('okna', 'demontaz');

  if (montazTak) addKoszt('Montaż okna', mbObwodu * montaz);
  if (hasOption('szczelny montaz')) addKoszt('Szczelny montaż', mbObwodu * szczelny);
  if (demontazTak) addKoszt('Demontaż okna', mbObwodu * demontaz);

  debug.okna = { mbObwodu, montaz, szczelny, demontaz };
}

// ---------------- DRZWI ZEWNĘTRZNE ----------------

if (category === 'drzwi_zew') {
  const montaz = getPrice('drzwi_zew', 'montaz kompletu');
  const naswietle = getPrice('drzwi_zew', 'naswietle');
  const demontaz = getPrice('drzwi_zew', 'demontaz');
  const kucie = getPrice('drzwi_zew', 'kucie');
  const nadproze = getPrice('drzwi_zew', 'nadproze');
  const szczelny = getPrice('drzwi_zew', 'szczelny montaz');

  if (montazTak) addKoszt('Montaż drzwi zewnętrznych', montaz);
  if (demontazTak) addKoszt('Demontaż drzwi zewnętrznych', demontaz);
  if (hasOption('naswietle', 'na swietle')) addKoszt('Naświetle', naswietle);

  if (hasOption('kucie wieksze')) addKoszt('Kucie większe', kucie * 2);
  else if (hasOption('kucie')) addKoszt('Kucie', kucie);

  if (hasOption('nadproze')) addKoszt('Nadproże', nadproze);
  if (hasOption('szczelny montaz')) addKoszt('Szczelny montaż', szczelny);

  debug.drzwi_zew = { montaz, naswietle, demontaz, kucie, nadproze, szczelny };
}

// ---------------- DRZWI WEWNĘTRZNE ----------------

if (category === 'drzwi_wew') {
  const montazKompletu = getPrice('drzwi_wew', 'montaz kompletu');
  const demontaz = getPrice('drzwi_wew', 'demontaz');
  const montazOpaski = getPrice('drzwi_wew', 'montaz opaski');
  const podciecieSkrzydla = getPrice('drzwi_wew', 'podciecie skrzydla');
  const podciecieOscieznicy = getPrice('drzwi_wew', 'podciecie oscieznicy');
  const montazTunelu = getPrice('drzwi_wew', 'montaz tunelu');
  const montazSamegoSkrzydla = getPrice('drzwi_wew', 'montaz samego skrzydla');

  if (montazTak) addKoszt('Montaż drzwi wewnętrznych', montazKompletu);
  if (demontazTak) addKoszt('Demontaż drzwi wewnętrznych', demontaz);
  if (hasOption('montaz opaski')) addKoszt('Montaż opaski', montazOpaski);
  if (hasOption('podciecie skrzydla', 'podciecie skrzydlo', 'podciecie: tak', 'podciecie tak', 'podciecie')) {
    addKoszt('Podcięcie skrzydła', podciecieSkrzydla);
  }
  if (hasOption('podciecie oscieznicy', 'podciecie oscieznica')) addKoszt('Podcięcie ościeżnicy', podciecieOscieznicy);
  if (hasOption('montaz tunelu')) addKoszt('Montaż tunelu', montazTunelu);
  if (hasOption('montaz samego skrzydla')) addKoszt('Montaż samego skrzydła', montazSamegoSkrzydla);

  debug.drzwi_wew = {
    montazKompletu,
    demontaz,
    montazOpaski,
    podciecieSkrzydla,
    podciecieOscieznicy,
    montazTunelu,
    montazSamegoSkrzydla
  };
}

// ---------------- PARAPETY ZEWNĘTRZNE ----------------

if (category === 'parapety_zewn') {
  const mb = toMeters(wymiar, jednostka);
  const montaz = getPrice('parapety_zewn', 'montaz');
  const demontaz = getPrice('parapety_zewn', 'demontaz');

  if (montazTak) addKoszt('Montaż parapetu zewnętrznego', mb * montaz);
  if (demontazTak) addKoszt('Demontaż parapetu zewnętrznego', mb * demontaz);

  debug.parapety_zewn = { mb, montaz, demontaz };
}

// ---------------- PARAPETY WEWNĘTRZNE ----------------

if (category === 'parapety_wewn') {
  const mb = toMeters(wymiar, jednostka);
  const montaz = getPrice('parapety_wewn', 'montaz');
  const demontaz = getPrice('parapety_wewn', 'demontaz');

  if (montazTak) addKoszt('Montaż parapetu wewnętrznego', mb * montaz);
  if (demontazTak) addKoszt('Demontaż parapetu wewnętrznego', mb * demontaz);

  debug.parapety_wewn = { mb, montaz, demontaz };
}

// ---------------- BRAMY ----------------

if (category === 'bramy') {
