const order = $('Pobranie klienta z arkusza Zamówienia1').first().json;
const notesRow = $('Zapisanie uwag').first().json || {};

const get = (obj, key) => String(obj?.[key] ?? '').trim();

const normalize = (v) =>
  String(v ?? '')
    .trim()
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '');

const isTak = (v) => ['tak', 'true', '1', 'yes'].includes(normalize(v));

const getField = (...values) => {
  for (const v of values) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
};

const toNumber = (value) => {
  const raw = String(value ?? '')
    .replace(/\s/g, '')
    .replace(',', '.')
    .trim();

  const num = Number(raw);
  return Number.isFinite(num) ? num : 0;
};

const normalizeInvoiceNotes = (value) => {
  const raw = String(value ?? '').trim();
  if (!raw) return '';

  const lowered = normalize(raw);

  const emptyPhrases = [
    'bez uwag',
    'brak uwag',
    'brak',
    'nic nie wpisuj',
    'nie dodawaj uwag',
    'puste',
    'bez',
    '-',
    'none'
  ];

  if (emptyPhrases.includes(lowered)) return '';

  return raw;
};

const today = new Date();

const addDaysISO = (date, days) => {
  const d = new Date(date);
  d.setDate(d.getDate() + days);
