      ...orderData,
      folder_client_id: folderId
    },
    binary: pdfItem.binary
  }
];

const rows = $input.all().map(i => i.json);

const str = (v) => String(v ?? '').trim();
const lower = (v) => str(v).toLowerCase();

const formatLocalISO = (date) => {
  const year = date.getFullYear();
  const month = String(date.getMonth() + 1).padStart(2, '0');
  const day = String(date.getDate()).padStart(2, '0');
  return `${year}-${month}-${day}`;
};

const toISODate = (value) => {
  if (!value) return '';
  const raw = String(value).trim();

  // jeśli przyjdzie już ISO
  const isoMatch = raw.match(/^(\d{4}-\d{2}-\d{2})/);
  if (isoMatch) return isoMatch[1];

  // format dd.mm.yyyy albo dd-mm-yyyy albo dd/mm/yyyy
  const plMatch = raw.match(/^(\d{1,2})[.\-/](\d{1,2})[.\-/](\d{4})$/);
  if (plMatch) {
    const day = plMatch[1].padStart(2, '0');
    const month = plMatch[2].padStart(2, '0');
    const year = plMatch[3];
    return `${year}-${month}-${day}`;
  }

  // próba standardowego parsowania
  const parsed = new Date(raw);
  if (!Number.isNaN(parsed.getTime())) {
    return formatLocalISO(parsed);
  }

  return '';
};

const today = new Date();
today.setHours(0, 0, 0, 0);

const targetDate = new Date(today);
targetDate.setDate(targetDate.getDate() + 2);

const targetISO = formatLocalISO(targetDate);

const filtered = rows.filter((row) => {
  const montazISO = toISODate(row['Data montażu']);

  const hasOrder = str(row['ID zamówienia (Fakturownia)']) !== '';
  const hasAdvance = str(row['ID faktury zaliczkowej']) !== '';
  const noFinalId = str(row['ID faktury końcowej']) === '';
  const finalFlag = lower(row['Faktura końcowa wystawiona (TAK/NIE)']);
  const status = lower(row['Status']);

  return (
    montazISO === targetISO &&
    hasOrder &&
    hasAdvance &&
    noFinalId &&
    finalFlag !== 'tak' &&
    status !== 'anulowane'
  );
});

return filtered.map(row => ({ json: row }));

