const currentClient = lower(
  current['Nazwisko'] ||
  current['Klient'] ||
  current['Klient (ID lub nazwisko)']
);

const existingTask = todoRows.find(row => {
  const idField = str(
    row['ID zamówienia'] ||
    row['ID wyceny'] ||
    row['ID'] ||
    row['id_zamowienia'] ||
    row['id_wyceny']
  );

  const clientField = lower(row['Klient (ID lub nazwisko)']);
  const taskField = lower(row['Zadanie']);
