    currentClient &&
    (
      clientField.includes(currentClient) ||
      taskField.includes(currentClient) ||
      notesField.includes(currentClient)
    );

  return (
    typeField === 'zamowienie' &&
    statusField !== 'zrobione' &&
    (
      hasThisId ||
      (hasThisProducer && hasThisClient)
    )
  );
