  const raw = String(v ?? '')
    .replace(/\s/g, '')
    .replace('zł', '')
    .replace('PLN', '')
    .replace(',', '.')
    .trim();

  const n = Number(raw);
  return Number.isFinite(n) ? n : 0;
};

const today = new Date().toISOString().slice(0, 10);

let buyerStreet = str(body.buyer_street);
let buyerPostCode = str(body.buyer_post_code);
let buyerCity = str(body.buyer_city);

const buyerAddress = str(body.buyer_address);

if (buyerAddress && (!buyerStreet || !buyerPostCode || !buyerCity)) {
  const match = buyerAddress.match(/^(.*?),?\s*(\d{2}-\d{3})\s+(.+)$/);
  if (match) {
    buyerStreet = str(match[1]);
    buyerPostCode = str(match[2]);
    buyerCity = str(match[3]);
  }
}

const paymentType = str(body.payment_type).toLowerCase() || 'przelew';

const issueDate = str(body.issue_date) || today;
const sellDate = str(body.sell_date) || issueDate;

const paymentTo =
  str(body.payment_to) ||
  (paymentType === 'przelew'
    ? new Date(new Date(sellDate).getTime() + 7 * 24 * 60 * 60 * 1000).toISOString().slice(0, 10)
    : sellDate);

const invoice = {
  kind: 'vat',
  issue_date: issueDate,
  sell_date: sellDate,
  payment_to: paymentTo,
  payment_type: paymentType,

  buyer_name: str(body.buyer_name),
  buyer_street: buyerStreet,
  buyer_post_code: buyerPostCode,
  buyer_city: buyerCity,
  buyer_country: str(body.buyer_country) || 'PL',
  buyer_tax_no: str(body.buyer_tax_no).toLowerCase() === 'brak' ? '' : str(body.buyer_tax_no),
  buyer_email: str(body.buyer_email),

  positions: [
    {
      name: str(body.product_name),
      quantity: num(body.quantity) || 1,
      total_price_gross: num(body.total_price_gross),
      tax: num(body.tax) || 23
    }
  ]
};

const missing = [];

if (!invoice.buyer_name) missing.push('buyer_name');
if (!invoice.buyer_street) missing.push('buyer_street');
if (!invoice.buyer_post_code) missing.push('buyer_post_code');
if (!invoice.buyer_city) missing.push('buyer_city');
if (!invoice.positions[0].name) missing.push('product_name');
if (!invoice.positions[0].total_price_gross) missing.push('total_price_gross');
if (!invoice.positions[0].tax) missing.push('tax');
if (!invoice.payment_type) missing.push('payment_type');

if (missing.length) {
  return [{
    json: {
      success: false,
      error_type: 'missing_manual_invoice_data',
      message: 'Brakuje danych do ręcznej faktury zwykłej.',
      missing_fields: missing
    }
  }];
}

return [{
  json: {
    success: true,
    api_token: 'FAKTUROWNIA_API_TOKEN',
    invoice,
    mode: 'manual'
  }
}];

