  const text = String(value ?? '').toUpperCase();
  const match = text.match(/RAL\s*([0-9]{4})|([0-9]{4})/);
  return match ? (match[1] || match[2]) : '';
};

const parseDimensions = (value, unitRaw) => {
  const text = String(value ?? '').replace(',', '.').toLowerCase();
  const unit = normalize(unitRaw || 'mm');

  const nums = [...text.matchAll(/(\d+(\.\d+)?)/g)].map(m => Number(m[1]));

  const lengthRaw = nums[0] || 0;
  const widthRaw = nums[1] || 0;

  const toMeters = (n) => {
    if (unit === 'm' || unit === 'metry' || unit === 'metr') return n;
    if (unit === 'cm') return n / 100;
    return n / 1000;
  };

  const toMm = (n) => {
    if (unit === 'm' || unit === 'metry' || unit === 'metr') return n * 1000;
    if (unit === 'cm') return n * 10;
    return n;
  };

  return {
    length_mb: round2(toMeters(lengthRaw)),
    width_mm: round2(toMm(widthRaw)),
    length_raw: lengthRaw,
    width_raw: widthRaw,
    unit
  };
};

// ---------------- DANE WYCENY ----------------

const produkt = normalize(data.produkt || data.produkty || data['Produkt']);
const kolor = data.kolor || data['Kolor'] || '';
const ral = extractRal(kolor);

const wymiary = data.wymiary || data['Wymiary'] || '';
const jednostka = data.jednostka || data['Jednostka (mm/cm/m)'] || data['Jednostka'] || 'mm';
const ilosc = toNumber(data.ilosc || data['Ilość'] || 1) || 1;

const szczegoly = normalize(data.szczegoly || data['Szczegóły'] || '');
const uwagi = normalize(data.uwagi || data['Uwagi'] || '');

const dims = parseDimensions(wymiary, jednostka);

const isParapetZewn = produkt.includes('parapet') && (
  produkt.includes('zewnetrzny') ||
  produkt.includes('zewn') ||
  produkt.includes('zew')
);

const isParapetWewn = produkt.includes('parapet') && (
  produkt.includes('wewnetrzny') ||
  produkt.includes('wewn') ||
  produkt.includes('wew')
);

const isParapet = isParapetZewn || isParapetWewn || produkt.includes('parapet');

// Jeśli to nie parapet, nic nie zmieniaj
if (!isParapet) {
  return [{
    json: {
      ...data,
      debug_cena_producenta: {
        reason: 'Produkt nie jest parapetem — pominięto ten node',
        produkt: data.produkt
      }
    }
  }];
}

// ---------------- CENA PARAPETU Z CENNIKA ----------------

const productRows = rows.filter(row => {
  const rowRal = extractRal(getField(row, ['ral', 'RAL']));
  const width = toNumber(getField(row, ['Szerokość (mm)', 'szerokość (mm)', 'szerokosc (mm)', 'Szerokosc (mm)']));
  const price = toNumber(getField(row, ['cena netto za mb', 'Cena netto za mb', 'cena_netto_za_mb']));

  return rowRal && width && price;
});

const matchedProductRow = productRows.find(row => {
  const rowRal = extractRal(getField(row, ['ral', 'RAL']));
  const width = toNumber(getField(row, ['Szerokość (mm)', 'szerokość (mm)', 'szerokosc (mm)', 'Szerokosc (mm)']));

  return rowRal === ral && Number(width) === Number(dims.width_mm);
});

let cenaZaMbProducent = 0;
let cenaParapetuProducent = 0;

if (matchedProductRow) {
  cenaZaMbProducent = toNumber(
    getField(matchedProductRow, [
      'cena netto za mb',
      'Cena netto za mb',
      'cena_netto_za_mb'
    ])
  );

  cenaParapetuProducent = round2(dims.length_mb * cenaZaMbProducent * ilosc);
}

// ---------------- ZAŚLEPKI ----------------

let rodzajZaslepek = '';

const zaslepkiText = `${szczegoly} ${uwagi}`;

if (zaslepkiText.includes('plastik')) {
  rodzajZaslepek = 'plastikowe';
} else if (zaslepkiText.includes('metal')) {
  rodzajZaslepek = 'metalowe';
}

const zaslepkiRows = rows.filter(row => {
  const rodzaj = normalize(getField(row, ['rodzaj', 'Rodzaj']));
  const cena = toNumber(getField(row, [
    'Komplet (2 zaślepki) netto',
    'Komplet (2 zaslepki) netto',
    'komplet netto',
    'Cena',
    'cena'
  ]));

  return rodzaj && cena;
});

const matchedZaslepkiRow = zaslepkiRows.find(row => {
  const rodzaj = normalize(getField(row, ['rodzaj', 'Rodzaj']));
  return rodzajZaslepek && rodzaj.includes(normalize(rodzajZaslepek.replace('owe', '')));
});

let cenaZaslepekProducent = 0;

if (matchedZaslepkiRow) {
  cenaZaslepekProducent = toNumber(
    getField(matchedZaslepkiRow, [
      'Komplet (2 zaślepki) netto',
      'Komplet (2 zaslepki) netto',
      'komplet netto',
      'Cena',
      'cena'
    ])
  );
}

// ---------------- FINAL ----------------

const cenaProduktuProducent = round2(cenaParapetuProducent + cenaZaslepekProducent);

const cenaProduktuKlient = toNumber(
  data.cena_produktu_klient ||
  data['Cena produktu klient'] ||
  data.cena_netto_produktu ||
  data['Cena netto produktu']
);

const zarobekProdukt = cenaProduktuProducent > 0
  ? round2(cenaProduktuKlient - cenaProduktuProducent)
  : data.zarobek_produkt || '';

return [{
  json: {
    ...data,

    cena_produktu_producent: cenaProduktuProducent || data.cena_produktu_producent || '',
    zarobek_produkt: zarobekProdukt,

    debug_cena_producenta: {
      produkt: data.produkt,
      kolor,
      ral,
      wymiary,
      jednostka,
      ilosc,
      length_mb: dims.length_mb,
      width_mm: dims.width_mm,
      cenaZaMbProducent,
      cenaParapetuProducent,
      rodzajZaslepek,
      cenaZaslepekProducent,
      cenaProduktuProducent,
      cenaProduktuKlient,
      zarobekProdukt,
      matchedProductRowFound: !!matchedProductRow,
      matchedZaslepkiRowFound: !!matchedZaslepkiRow
    }
  }
}];

const data = $json;

const toNumber = (v) => {
  if (v === undefined || v === null || v === '') return 0;
  return Number(String(v).replace(',', '.').replace(/\s/g, '')) || 0;
};

const round2 = (n) => Math.round((n + Number.EPSILON) * 100) / 100;

const normalize = (v) =>
  String(v || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .trim();

const produkt = normalize(data.produkt);
const typKlienta = normalize(data.typ_klienta);
const wariant = normalize(data.wariant_wyceny_wybrany || '');

const czyDrzwi = produkt.includes('drzwi');
const czyFirma = typKlienta.includes('firma');

const montazBezMontazu =
  String(data.montaz_bez_montazu || '').toUpperCase() === 'TAK';

const czyUslugaMontazu =
  String(data.czy_usluga_montazu || '').toUpperCase() === 'TAK' ||
  montazBezMontazu ||
  (wariant.includes('z montazem') && !wariant.includes('bez montazu'));

let cenaNettoProduktu = toNumber(data.cena_netto_produktu);
let cenaMontazu = toNumber(data.cena_montazu);
let cenaBruttoBezMontazu = toNumber(data.cena_brutto_bez_montazu);
let cenaBruttoZMontazem = toNumber(data.cena_brutto_z_montazem);
let cenaWyceny = toNumber(data.cena_wyceny);

let cenaKatalogowaBrutto = toNumber(data.cena_katalogowa_brutto);
let cenaKatalogowaNetto = toNumber(data.cena_katalogowa_netto);
let cenaProduktuKlient = toNumber(data.cena_produktu_klient);
let cenaProduktuProducent = toNumber(data.cena_produktu_producent);
let vat = toNumber(data.vat);

// ---------------- DRZWI ----------------

if (czyDrzwi) {
  cenaKatalogowaBrutto = toNumber(
    data.cena_katalogowa_brutto ||
    data.cena_brutto_bez_montazu ||
    data.cena_wyceny
  );

  if (cenaKatalogowaBrutto > 0) {
    const nettoKatalog23 = round2(cenaKatalogowaBrutto / 1.23);
    const nettoPrzy8 = round2(cenaKatalogowaBrutto / 1.08);

    cenaProduktuProducent = round2(nettoKatalog23 * 0.70);

    if (czyFirma) {
      vat = 23;
      cenaKatalogowaNetto = nettoKatalog23;
      cenaProduktuKlient = nettoKatalog23;
      cenaNettoProduktu = nettoKatalog23;

      cenaBruttoBezMontazu = round2(cenaProduktuKlient * 1.23);
      cenaBruttoZMontazem = round2(cenaProduktuKlient * 1.23 + cenaMontazu);
      cenaWyceny = czyUslugaMontazu ? cenaBruttoZMontazem : cenaBruttoBezMontazu;
    } else if (czyUslugaMontazu || montazBezMontazu) {
      vat = 8;
      cenaKatalogowaNetto = nettoPrzy8;
      cenaProduktuKlient = nettoPrzy8;
      cenaNettoProduktu = nettoPrzy8;

      cenaBruttoBezMontazu = round2(nettoKatalog23 * 1.23);
      cenaBruttoZMontazem = round2(cenaKatalogowaBrutto + cenaMontazu);
      cenaWyceny = cenaBruttoZMontazem;
    } else {
      vat = 23;
      cenaKatalogowaNetto = nettoKatalog23;
      cenaProduktuKlient = nettoKatalog23;
      cenaNettoProduktu = nettoKatalog23;

      cenaBruttoBezMontazu = round2(cenaKatalogowaBrutto);
      cenaBruttoZMontazem = round2(nettoPrzy8 * 1.08 + cenaMontazu);
      cenaWyceny = cenaBruttoBezMontazu;
    }
  }
}

// ---------------- INNE PRODUKTY ----------------

if (!czyDrzwi) {
  cenaKatalogowaNetto = cenaNettoProduktu;
  cenaProduktuKlient = cenaNettoProduktu;

  if (czyFirma) {
    vat = 23;
  } else if (czyUslugaMontazu || montazBezMontazu) {
    vat = 8;
  } else {
    vat = 23;
  }

  cenaBruttoBezMontazu = round2(cenaNettoProduktu * 1.23);
  cenaBruttoZMontazem = round2(cenaNettoProduktu * (1 + vat / 100) + cenaMontazu);

  cenaKatalogowaBrutto = cenaBruttoBezMontazu;

  cenaWyceny = cenaKatalogowaBrutto;
}

// ---------------- ZAPIS ----------------

data.cena_katalogowa_brutto = round2(cenaKatalogowaBrutto);
data.cena_katalogowa_netto = round2(cenaKatalogowaNetto);
data.vat = vat;

data.cena_netto_produktu = round2(cenaNettoProduktu);
data.cena_produktu_klient = round2(cenaProduktuKlient);
data.cena_produktu_producent = round2(cenaProduktuProducent);

data.cena_brutto_bez_montazu = round2(cenaBruttoBezMontazu);
data.cena_brutto_z_montazem = round2(cenaBruttoZMontazem);
data.cena_wyceny = round2(cenaWyceny);

data.zarobek_produkt =
  cenaProduktuProducent > 0
    ? round2(cenaProduktuKlient - cenaProduktuProducent)
    : '';
// FINALNA KWOTA WYCENY DLA WSZYSTKICH PRODUKTÓW

if (!czyDrzwi) {
  data.cena_wyceny =
    (czyUslugaMontazu || montazBezMontazu)
      ? round2(cenaBruttoZMontazem)
      : round2(cenaBruttoBezMontazu);
}

return [{ json: data }];

