parameters.jsCode:
const input = $('update-quote').first().json.body || {};
const rows = $input.all().map(i => i.json);

const normalize = (v) =>
  String(v || '')
    .trim()
    .toLowerCase();

const normalizePhone = (v) =>
  String(v || '')
    .replace(/\s+/g, '')
    .replace(/[^0-9+]/g, '');

const id = normalize(input.id_wyceny);
const phone = normalizePhone(input.telefon);
const nazwisko = normalize(input.nazwisko);
const email = normalize(input.email);

let matches = [];

if (id) {
  matches = rows.filter(r => normalize(r['ID']) === id || normalize(r['ID wyceny']) === id);
} else if (phone) {
  matches = rows.filter(r => normalizePhone(r['Telefon']) === phone);
} else if (nazwisko) {
  matches = rows.filter(r => normalize(r['Nazwisko']) === nazwisko);
} else if (email) {
  matches = rows.filter(r => normalize(r['Email']) === email);
}

matches = matches.filter(r => normalize(r['Status rekordu']) !== 'usunięty');

return [{
  json: {
    found_count: matches.length,
    matched_rows: matches,
    input
  }
}];

const rows = $input.all().map(i => i.json);
const producerRows = $('Rozpoznawanie producenta').all().map(i => i.json);

const today = new Date().toISOString().slice(0, 10);

const get = (row, name) => {
  const key = Object.keys(row || {}).find(k => String(k).trim() === name);
  return key ? row[key] : '';
};

const norm = (v) =>
  String(v || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .trim();

const str = (v) => String(v ?? '').trim();

const findProducerRow = (row) => {
  const rowNumber = str(row.row_number);
  const idWyceny = str(get(row, 'ID wyceny'));

  return producerRows.find(r =>
    str(r.row_number) === rowNumber ||
    str(get(r, 'ID wyceny')) === idWyceny
  ) || {};
};

const detectProducer = (row) => {
  const matchedProducerRow = findProducerRow(row);

  const producerFromCurrent = str(get(row, 'Producent'));
  const producerFromMatched = str(get(matchedProducerRow, 'Producent'));

  if (producerFromCurrent) return producerFromCurrent;
  if (producerFromMatched) return producerFromMatched;

  const text = norm([
    get(row, 'Produkty (opis)'),
    get(row, 'Model'),
    get(row, 'Szczegóły'),
    get(row, 'Uwagi'),
    get(matchedProducerRow, 'Produkty (opis)'),
    get(matchedProducerRow, 'Model'),
    get(matchedProducerRow, 'Szczegóły'),
    get(matchedProducerRow, 'Uwagi')
  ].filter(Boolean).join(' '));

  if (text.includes('drzwi')) return 'Eurodoor';
  if (text.includes('okno') || text.includes('okna') || text.includes('web')) return 'Eko Okna';
  if (text.includes('parapet')) return 'Medos';
  if (text.includes('brama')) return 'Bramet';

  if (
    text.includes('roleta') ||
    text.includes('zaluzja') ||
    text.includes('żaluzja') ||
    text.includes('moskitiera')
  ) return 'Fill';

  return 'Do ustalenia';
};

const output = [];

for (const row of rows) {
  const matchedProducerRow = findProducerRow(row);
  const producent = detectProducer(row);

  const imie =
    str(get(row, 'Imię')) ||
    str(get(matchedProducerRow, 'Imię'));

  const nazwisko =
    str(get(row, 'Nazwisko')) ||
    str(get(matchedProducerRow, 'Nazwisko'));

  const telefon =
    str(get(row, 'Telefon')) ||
    str(get(matchedProducerRow, 'Telefon'));

  const klient =
    [imie, nazwisko].filter(Boolean).join(' ') ||
    telefon ||
    str(get(row, 'Klient')) ||
    str(row.row_number);

  const adres = [
    get(row, 'Ulica') || get(matchedProducerRow, 'Ulica'),
    get(row, 'Kod pocztowy') || get(matchedProducerRow, 'Kod pocztowy'),
    get(row, 'Miasto') || get(matchedProducerRow, 'Miasto')
  ]
    .map(str)
    .filter(Boolean)
    .join(', ');

  const produkty =
    str(get(row, 'Produkty (opis)')) ||
    str(get(matchedProducerRow, 'Produkty (opis)')) ||
    str(get(row, 'Model')) ||
    str(get(matchedProducerRow, 'Model'));

  // ID zamówienia w TODO ma być ID wyceny
  const idWyceny =
    str(get(row, 'ID wyceny')) ||
    str(get(matchedProducerRow, 'ID wyceny')) ||
    str(row.row_number);

  // ID TODO ma być techniczne, np. TODO-ZAM-6-1779024131538
  const todoId = `TODO-ZAM-${row.row_number}-${Date.now()}`;

  output.push({
    json: {
      'Data utworzenia': today,

      'Zadanie': `Zamówić u producenta — ${producent}`,

      'Klient (ID lub nazwisko)': klient,

      'Status (do zrobienia / w trakcie / zrobione)': 'do zrobienia',

      'Uwagi': [
        `Producent: ${producent}`,
        telefon ? `Telefon: ${telefon}` : '',
        adres ? `Adres: ${adres}` : '',
        produkty ? `Produkty: ${produkty}` : '',
        'Zamówienie nie zostało wysłane automatycznie. Wysyłka dopiero po komendzie właściciela.'
      ].filter(Boolean).join('\n'),

      'Typ (zamówienie / reklamacja / faktura / inne)': 'zamówienie',

      'Termin': today,

      'Priorytet (niski / średni / wysoki)': 'wysoki',

      // tutaj zapisuje ID wyceny
      'ID zamówienia': idWyceny,

      'Przypomnienie 3 dni': '',
      'Przypomnienie 7 dni': '',
      'Przypomnienie 14 dni': '',
      'Przypomnienie reklamacja 14 dni': '',
      'Przypomnienie reklamacja 40 dni': '',

      'Data ostatniej aktualizacji': today,

      'Data zamknięcia': '',

      'Czy powiadomienie wysłane (TAK/NIE)': 'NIE',

      // tutaj techniczne ID TODO
      'ID': todoId,

      'Link do pliku/faktury/maila':
        str(get(row, 'Link do folderu klienta')) ||
        str(get(matchedProducerRow, 'Link do folderu klienta'))
    }
  });
}

return output;

const currentItems = $('Budowa todo').all().map(i => i.json);
const todos = $('Pobranie TODO').all().map(i => i.json);

const norm = (v) =>
  String(v || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[–—]/g, '-')
    .replace(/\s+/g, ' ')
    .trim();

const output = [];

for (const current of currentItems) {
  const currentOrderId = norm(current['ID zamówienia']);
  const currentType = norm(current['Typ (zamówienie / reklamacja / faktura / inne)']);
  const currentTask = norm(current['Zadanie']);
  const currentClient = norm(current['Klient (ID lub nazwisko)']);

  const existing = todos.find(t => {
    const todoOrderId = norm(t['ID zamówienia']);
    const todoType = norm(t['Typ (zamówienie / reklamacja / faktura / inne)']);
    const todoStatus = norm(t['Status (do zrobienia / w trakcie / zrobione)']);
    const todoTask = norm(t['Zadanie']);
    const todoClient = norm(t['Klient (ID lub nazwisko)']);

    if (todoStatus === 'zrobione') return false;

    // główne zabezpieczenie: ten sam ID wyceny / zamówienia
    if (
      currentOrderId &&
      todoOrderId &&
      currentOrderId === todoOrderId &&
      todoType === currentType
    ) {
      return true;
    }

    // fallback: ten sam klient + to samo zadanie
    if (
      currentClient &&
      todoClient &&
      currentClient === todoClient &&
      todoTask === currentTask &&
      todoType === currentType
    ) {
      return true;
    }

    return false;
  });

  output.push({
    json: {
      ...current,
      task_exists: existing ? 'TAK' : 'NIE',
      existing_task_id: existing?.ID || ''
    }
  });
}

return output;

const input = $('send-email').first().json.body || $('send-email').first().json;
const contractors = $('Kontrahenci — pobierz').all().map(i => i.json);

const norm = (v) =>
  String(v || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .trim();

const str = (v) => String(v ?? '').trim();

const modeRaw = norm(input.mode || input.tryb || 'draft');

const mode =
  modeRaw === 'send' ||
  modeRaw === 'wyslij' ||
  modeRaw === 'wyślij'
    ? 'send'
    : 'draft';

const kontrahentInput = norm(
  input.kontrahent ||
  input.odbiorca ||
  ''
);

const typMaila = norm(
  input.typ_maila ||
  input.typ ||
  'inne'
);

const produkt = norm(
  input.produkt ||
  input.kategoria ||
  ''
);

let to = str(input.to || input.email || '');

const activeContractors = contractors.filter(c =>
  norm(c['Aktywny (TAK/NIE)'] || 'TAK') !== 'nie'
);

let contractor = null;

/*
========================================
1. DOKŁADNE DOPASOWANIE KONTRAHENTA
========================================
*/

if (!to && kontrahentInput) {

  contractor = activeContractors.find(c => {
    const id = norm(c['ID']);
    const nazwa = norm(c['Nazwa kontrahenta']);

    return (
      id === kontrahentInput ||
      nazwa === kontrahentInput
    );
  });

  /*
  ========================================
  2. LUŹNIEJSZE DOPASOWANIE
  ========================================
  */

  if (!contractor) {

    contractor = activeContractors.find(c => {

      const nazwa = norm(c['Nazwa kontrahenta']);
      const folder = norm(c['Folder kontrahenta']);
      const domain = norm(c['Domena']);

      return (
        nazwa.includes(kontrahentInput) ||
        kontrahentInput.includes(nazwa) ||

        folder === kontrahentInput ||

        (
          domain &&
          (
            kontrahentInput.includes(domain) ||
            domain.includes(kontrahentInput)
          )
        )
      );
    });
  }
}

/*
========================================
3. DOPASOWANIE PO PRODUKCIE
========================================
*/

if (!to && produkt && !contractor) {

  contractor = activeContractors.find(c => {

    const prod = norm(c['Produkt']);

    if (!prod) return false;

    return (
      prod === produkt ||
      prod.includes(produkt) ||
      produkt.includes(prod)
    );
  });
}

/*
========================================
4. WYBÓR EMAILA
========================================
*/

if (contractor && !to) {

  const emailMain = str(contractor['Email główny']);
  const emailOrder = str(contractor['Email zamówienia']);
  const emailComplaint = str(contractor['Email reklamacje']);
  const emailWz = str(contractor['Email dostawy / WZ']);
  const emailGuardian = str(contractor['Email opiekuna']);

  if (typMaila === 'reklamacja') {

    to =
      emailComplaint ||
      emailGuardian ||
      emailMain;

  } else if (
    typMaila.includes('zam')
  ) {

    to =
      emailOrder ||
      emailGuardian ||
      emailMain;

  } else if (
    typMaila === 'dostawa' ||
    typMaila === 'wz'
  ) {

    to =
      emailWz ||
      emailGuardian ||
      emailMain;

  } else {

    to =
      emailGuardian ||
      emailMain;
  }
}

/*
========================================
5. WALIDACJA
========================================
*/

