const subjectSearch = norm(input.subject || input.temat || '');
const containsSearch = norm(input.contains || input.fragment || input.tresc || '');

const matches = drafts.map(d => {
  const draftId = d.id || d.draftId || d.draft_id || '';
  const messageId = d.message?.id || d.messageId || d.message_id || '';

  const to = norm(d.to || d.To || d.message?.payload?.headers?.find(h => h.name?.toLowerCase() === 'to')?.value || '');
