  const snippet = norm(d.snippet || d.body || d.text || '');

  let score = 0;

  if (toSearch && to.includes(toSearch)) score += 50;
  if (subjectSearch && subject.includes(subjectSearch)) score += 50;
  if (containsSearch && (subject.includes(containsSearch) || snippet.includes(containsSearch))) score += 40;

  return {
    draft_id: draftId,
    message_id: messageId,
    to,
    subject,
    snippet,
    score
