const zamowienia = $('Zamówienia — pobierz2').all().map(i => i.json);
const todos = $('TODO — pobierz').all().map(i => i.json);

const norm = (v) =>
  String(v || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .trim();

const cleanPhone = (v) =>
  String(v || '')
    .replace(/\s+/g, '')
    .replace(/[^0-9+]/g, '');

const get = (row, name) => {
  const key = Object.keys(row).find(k => String(k).trim() === name);
  return key ? row[key] : '';
};

const subject = String(mail.subject || mail.Subject || '').trim();
const fromRaw = String(mail.from || mail.From || mail.sender || '').trim();
const fromEmailMatch = fromRaw.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
const fromEmail = fromEmailMatch ? fromEmailMatch[0].toLowerCase() : '';

const text = String(
  mail.textPlain ||
  mail.textHtml ||
  mail.text ||
  mail.html ||
  mail.body ||
  mail.snippet ||
  ''
);

const allNorm = norm(`${subject} ${fromRaw} ${text}`);

const today = new Date().toISOString().slice(0, 10);

// BLOKADY
const ownMail =
  fromEmail.includes('contact@company-abc.com');

const autoReply =
  allNorm.includes('automatic reply') ||
  allNorm.includes('auto reply') ||
  allNorm.includes('out of office') ||
  allNorm.includes('poza biurem') ||
  allNorm.includes('autoodpowiedz');

const newsletter =
  allNorm.includes('newsletter') ||
  allNorm.includes('unsubscribe') ||
  allNorm.includes('wypisz');

if (ownMail || autoReply || newsletter) {
  return [{
    json: {
      create_todo: 'NIE',
      reason: 'Mail własny / auto reply / newsletter.'
    }
  }];
}

// ROZPOZNANIE INTENCJI KLIENTA
const quoteRequest =
  allNorm.includes('wycena') ||
  allNorm.includes('oferta') ||
  allNorm.includes('prosze o wycene') ||
  allNorm.includes('prosze o oferte') ||
  allNorm.includes('ile koszt') ||
  allNorm.includes('jaka cena') ||
  allNorm.includes('chcialbym zapytac') ||
  allNorm.includes('chciałbym zapytać');

const quoteAccepted =
  allNorm.includes('akceptuje') ||
  allNorm.includes('akceptuję') ||
  allNorm.includes('zgadzam sie') ||
  allNorm.includes('zgadzam się') ||
  allNorm.includes('robimy') ||
  allNorm.includes('zamawiam') ||
  allNorm.includes('prosze zamawiac') ||
  allNorm.includes('proszę zamawiać') ||
  allNorm.includes('wchodzimy w to') ||
  allNorm.includes('pasuje mi') ||
  allNorm.includes('potwierdzam wycene') ||
  allNorm.includes('potwierdzam wycenę');

const quoteRejected =
  allNorm.includes('rezygnuje') ||
  allNorm.includes('rezygnuję') ||
  allNorm.includes('nieaktualne') ||
  allNorm.includes('za drogo') ||
  allNorm.includes('nie decyduje sie') ||
  allNorm.includes('nie decyduję się');

const quoteChange =
  allNorm.includes('zmiana') ||
  allNorm.includes('zmienic') ||
  allNorm.includes('zmienić') ||
  allNorm.includes('inny kolor') ||
  allNorm.includes('inny wymiar') ||
  allNorm.includes('inne wymiary') ||
  allNorm.includes('bez montazu') ||
  allNorm.includes('bez montażu') ||
  allNorm.includes('z montazem') ||
  allNorm.includes('z montażem');

// jeśli to nie dotyczy wyceny, nie robimy nic
if (!quoteRequest && !quoteAccepted && !quoteRejected && !quoteChange) {
  return [{
    json: {
      create_todo: 'NIE',
      reason: 'Mail nie dotyczy procesu wyceny.'
    }
  }];
}

// DOPASOWANIE KLIENTA
const emailNorm = norm(fromEmail);

const scoreRow = (row) => {
  let score = 0;

  const rowEmail = norm(get(row, 'Email'));
  const rowPhone = cleanPhone(get(row, 'Telefon'));
  const rowName = norm(`${get(row, 'Imię')} ${get(row, 'Nazwisko')}`);
  const rowNazwisko = norm(get(row, 'Nazwisko'));
  const rowStreet = norm(get(row, 'Ulica'));
  const rowCity = norm(get(row, 'Miasto'));

  if (emailNorm && rowEmail && emailNorm === rowEmail) score += 100;
  if (rowPhone && allNorm.includes(rowPhone)) score += 90;
  if (rowNazwisko && allNorm.includes(rowNazwisko)) score += 50;
  if (rowName && allNorm.includes(rowName)) score += 60;
  if (rowStreet && allNorm.includes(rowStreet)) score += 30;
  if (rowCity && allNorm.includes(rowCity)) score += 20;

  return score;
};

const matchedQuotes = wyceny
  .map(r => ({ ...r, _score: scoreRow(r) }))
  .filter(r => r._score >= 50)
  .sort((a, b) => b._score - a._score);

const matchedOrders = zamowienia
  .map(r => ({ ...r, _score: scoreRow(r) }))
  .filter(r => r._score >= 50)
  .sort((a, b) => b._score - a._score);

const quote = matchedQuotes[0] || null;
const order = matchedOrders[0] || null;

// jeśli klient już jest w Zamówieniach, nie monitorujemy jako wyceny
if (order && order._score >= 100) {
  return [{
    json: {
      create_todo: 'NIE',
      reason: 'Klient jest już w Zamówieniach.'
    }
  }];
}

const klient =
  quote
    ? `${get(quote, 'Imię')} ${get(quote, 'Nazwisko')}`.trim() || get(quote, 'Nazwisko') || fromEmail
    : fromEmail || fromRaw;

const idWyceny =
  quote
    ? (
        get(quote, 'ID (unikalny numer)') ||
        get(quote, 'ID wyceny')
      )
    : '';
const telefon = quote ? get(quote, 'Telefon') : '';

let zadanie = '';
let priorytet = 'średni';
let typ = 'zamówienie';

if (quoteAccepted) {
  zadanie = `Klient zaakceptował wycenę — przygotować zamówienie: ${klient}`;
  priorytet = 'wysoki';
} else if (quoteRejected) {
  zadanie = `Klient zrezygnował / odrzucił wycenę: ${klient}`;
  priorytet = 'niski';
} else if (quoteChange) {
  zadanie = `Klient chce zmianę w wycenie: ${klient}`;
  priorytet = 'średni';
} else if (quoteRequest && quote) {
  zadanie = `Klient odpisał w sprawie istniejącej wyceny: ${klient}`;
  priorytet = 'średni';
} else if (quoteRequest && !quote) {
  zadanie = `Przygotować nową wycenę z maila: ${subject}`;
  priorytet = 'średni';
}

// ANTY-DUPLIKAT TODO
const openTodos = todos.filter(t =>
  norm(get(t, 'Status (do zrobienia / w trakcie / zrobione)')) !== 'zrobione'
);

const duplicate = openTodos.some(t => {
  const tText = norm([
    get(t, 'Zadanie'),
    get(t, 'Klient (ID lub nazwisko)'),
    get(t, 'ID zamówienia'),
    get(t, 'Uwagi')
  ].join(' '));

  if (idWyceny && tText.includes(norm(idWyceny))) return true;
  if (telefon && cleanPhone(tText).includes(cleanPhone(telefon))) return true;
  if (klient && tText.includes(norm(klient))) return true;

  return false;
});

if (duplicate) {
  return [{
    json: {
      create_todo: 'NIE',
      reason: 'Podobne otwarte TODO już istnieje.',
      klient,
      id_wyceny: idWyceny
    }
  }];
}

return [{
  json: {
    create_todo: 'TAK',
    typ_maila: quoteAccepted
      ? 'KLIENT_AKCEPTUJE_WYCENE'
      : quoteRejected
        ? 'KLIENT_REZYGNUJE_Z_WYCENY'
        : quoteChange
          ? 'KLIENT_ZMIANA_WYCENY'
          : 'KLIENT_WYCENA',

    todo: {
      id: `TODO-${Date.now()}`,
      data_utworzenia: today,
      zadanie,
      klient,
      priorytet,
      status: 'do zrobienia',
      termin: today,
      typ,
      przypomnienie_3_dni: '',
      przypomnienie_7_dni: '',
      przypomnienie_14_dni: '',
      data_ostatniej_aktualizacji: today,
      czy_powiadomienie_wyslane: 'NIE',
      id_zamowienia: idWyceny,
      uwagi: [
        `Mail od: ${fromRaw}`,
        `Temat: ${subject}`,
        idWyceny ? `ID wyceny: ${idWyceny}` : '',
        telefon ? `Telefon: ${telefon}` : '',
        `Źródło: monitoring wycen z maila`
      ].filter(Boolean).join('\n'),
      link_maila: mail.webViewLink || mail.link || mail.gmail_link || ''
    }
  }
}];

const wyceny = $('Wyceny — pobierz1').all().map(i => i.json);
const zamowienia = $('Zamówienia — pobierz3').all().map(i => i.json);
const todos = $('TODO — pobierz1').all().map(i => i.json);

const norm = (v) =>
  String(v || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .trim();

const cleanPhone = (v) =>
  String(v || '')
    .replace(/\s+/g, '')
    .replace(/[^0-9+]/g, '');

const get = (row, name) => {
  const key = Object.keys(row).find(k => String(k).trim() === name);
  return key ? row[key] : '';
};

const getRecordId = (row) =>
  get(row, 'ID (unikalny numer)') ||
  get(row, 'ID wyceny') ||
  get(row, 'ID');

const parseDate = (value) => {
  if (!value) return null;

  const raw = String(value).trim();

  let m = raw.match(/^(\d{4}-\d{2}-\d{2})/);
  if (m) {
    const d = new Date(m[1]);
    d.setHours(0, 0, 0, 0);
    return d;
  }

  m = raw.match(/^(\d{1,2})[./-](\d{1,2})[./-](\d{4})/);
  if (m) {
    const d = new Date(`${m[3]}-${m[2].padStart(2, '0')}-${m[1].padStart(2, '0')}`);
    d.setHours(0, 0, 0, 0);
    return d;
  }

  const d = new Date(raw);
  if (Number.isNaN(d.getTime())) return null;

  d.setHours(0, 0, 0, 0);
  return d;
};

const today = new Date();
today.setHours(0, 0, 0, 0);
const todayISO = today.toISOString().slice(0, 10);

const openTodos = todos.filter(t =>
  norm(get(t, 'Status (do zrobienia / w trakcie / zrobione)')) !== 'zrobione'
);

const outputs = [];

const hasOrder = (quote) => {
  const qPhone = cleanPhone(get(quote, 'Telefon'));
  const qEmail = norm(get(quote, 'Email'));
  const qNazwisko = norm(get(quote, 'Nazwisko'));
  const qId = norm(getRecordId(quote));

  return zamowienia.some(o => {
    const oPhone = cleanPhone(get(o, 'Telefon'));
    const oEmail = norm(get(o, 'Email'));
    const oNazwisko = norm(get(o, 'Nazwisko'));
    const oId = norm(getRecordId(o));

    if (qId && oId && qId === oId) return true;
    if (qPhone && oPhone && qPhone === oPhone) return true;
    if (qEmail && oEmail && qEmail === oEmail) return true;
    if (qNazwisko && oNazwisko && qNazwisko === oNazwisko) return true;

    return false;
  });
};

const hasOpenReminderTodo = (quote) => {
  const qId = norm(getRecordId(quote));
  const qPhone = cleanPhone(get(quote, 'Telefon'));
  const qNazwisko = norm(get(quote, 'Nazwisko'));

  return openTodos.some(t => {
    const text = norm([
      get(t, 'Zadanie'),
      get(t, 'Klient (ID lub nazwisko)'),
      get(t, 'ID zamówienia'),
      get(t, 'Uwagi')
    ].join(' '));

    const phoneText = cleanPhone(text);

    const isQuoteReminder =
      text.includes('przypomniec sie klientowi') ||
      text.includes('przypomnieć się klientowi') ||
      text.includes('brak decyzji po wycenie') ||
      text.includes('brak odpowiedzi na wycene') ||
      text.includes('brak odpowiedzi na wycenę');

    if (!isQuoteReminder) return false;

    if (qId && text.includes(qId)) return true;
    if (qPhone && phoneText.includes(qPhone)) return true;
    if (qNazwisko && text.includes(qNazwisko)) return true;

    return false;
  });
};

for (const q of wyceny) {
  const status = norm(get(q, 'Status'));

  if (
    status.includes('anul') ||
    status.includes('rezygn') ||
    status.includes('zamow') ||
    status.includes('zamów')
  ) {
    continue;
  }

  if (hasOrder(q)) continue;
  if (hasOpenReminderTodo(q)) continue;

  const created =
    parseDate(get(q, 'Data utworzenia')) ||
    parseDate(get(q, 'Data ostatniej aktualizacji')) ||
    parseDate(get(q, 'Data wyceny'));

  if (!created) continue;

  const diffDays = Math.floor((today - created) / (1000 * 60 * 60 * 24));

  if (diffDays < 3) continue;

  const klient =
    `${get(q, 'Imię')} ${get(q, 'Nazwisko')}`.trim() ||
    get(q, 'Nazwisko') ||
    get(q, 'Email') ||
    get(q, 'Telefon');

  const idWyceny = getRecordId(q);
  const telefon = get(q, 'Telefon');

  let priorytet = 'średni';
  if (diffDays >= 7) priorytet = 'wysoki';

  outputs.push({
    json: {
      id: `TODO-${Date.now()}-${outputs.length + 1}`,
      data_utworzenia: todayISO,
      zadanie: `Przypomnieć się klientowi — brak decyzji po wycenie: ${klient}`,
      klient,
      priorytet,
      status: 'do zrobienia',
      termin: todayISO,
      typ: 'zamówienie',
      przypomnienie_3_dni: '',
      przypomnienie_7_dni: '',
      przypomnienie_14_dni: '',
      data_ostatniej_aktualizacji: todayISO,
      czy_powiadomienie_wyslane: 'NIE',
      id_zamowienia: idWyceny,
      uwagi: [
        `Wycena otwarta od ${diffDays} dni.`,
        idWyceny ? `ID wyceny: ${idWyceny}` : '',
        telefon ? `Telefon: ${telefon}` : '',
        `Źródło: monitoring starych wycen`
      ].filter(Boolean).join('\n'),
      link_maila: ''
    }
  });
}

return outputs;

const input = $('send-email').first().json.body || $('send-email').first().json;

const orders = $('Pobierz arkusz Zamówienia').all().map(i => i.json);
const contractors = $('Pobierz arkusz Kontrahenci').all().map(i => i.json);

const norm = (v) =>
  String(v || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/\s+/g, ' ')
    .trim();

const str = (v) => String(v ?? '').trim();

const cleanPhone = (v) =>
  String(v || '')
    .replace(/\s+/g, '')
    .replace(/[^0-9+]/g, '');

const get = (row, name) => {
  const key = Object.keys(row).find(k => String(k).trim() === name);
  return key ? row[key] : '';
};

const splitMulti = (value) =>
  String(value || '')
    .replace(/\n/g, '|')
    .replace(/;/g, '|')
    .split('|')
    .map(v => v.trim())
    .filter(Boolean);

const inputClient = norm(input.klient || input.nazwisko || input.imie || '');
const inputPhone = cleanPhone(input.telefon || '');
const inputId = norm(input.id_zamowienia || input.id_zamowienia_wewnetrznego || input.id_wyceny || input.id || '');

const findOrder = () => {
  return orders.map(r => {
    let score = 0;

    const fullName = norm(`${get(r, 'Imię')} ${get(r, 'Nazwisko')}`);
    const surname = norm(get(r, 'Nazwisko'));
    const name = norm(get(r, 'Imię'));
    const phone = cleanPhone(get(r, 'Telefon'));

    const id1 = norm(get(r, 'ID zamówienia wewnętrznego'));
    const id2 = norm(get(r, 'ID zamówienia (Fakturownia)'));
    const id3 = norm(get(r, 'ID wyceny'));

    if (inputPhone && phone === inputPhone) score += 100;
    if (inputId && [id1, id2, id3].includes(inputId)) score += 100;
    if (inputClient && fullName.includes(inputClient)) score += 70;
    if (inputClient && surname.includes(inputClient)) score += 60;
    if (inputClient && name.includes(inputClient)) score += 40;

    return { ...r, _score: score };
  })
  .filter(r => r._score >= 40)
  .sort((a, b) => b._score - a._score);
};

const matched = findOrder();

if (matched.length === 0) {
  return [{
    json: {
      success: false,
      error: 'Nie znaleziono zamówienia dla podanego klienta / telefonu / ID.'
    }
  }];
}

if (matched.length > 1 && !inputPhone && !inputId) {
  return [{
    json: {
      success: false,
      error: 'Znaleziono więcej niż jedno zamówienie. Podaj telefon albo ID zamówienia.',
      matches: matched.slice(0, 5).map(r => ({
        klient: `${get(r, 'Imię')} ${get(r, 'Nazwisko')}`.trim(),
        telefon: get(r, 'Telefon'),
        produkt: get(r, 'Produkty (opis)'),
        model: get(r, 'Model'),
        row_number: r.row_number
      }))
    }
  }];
}

const order = matched[0];

const productText = norm([
  get(order, 'Produkty (opis)'),
  get(order, 'Produkt'),
  get(order, 'Model'),
  get(order, 'Szczegóły'),
  get(order, 'Uwagi'),
  get(order, 'Producent')
].join(' '));

const detectProducer = () => {
  if (productText.includes('drzwi')) return 'Eurodoor';
  if (productText.includes('okno') || productText.includes('okna')) return 'Eko Okna';
  if (productText.includes('parapet')) return 'Medos';
  if (
    productText.includes('roleta') ||
    productText.includes('rolety') ||
    productText.includes('zaluz') ||
    productText.includes('moskit')
  ) return 'Fill';
  if (productText.includes('brama') || productText.includes('bramy')) return 'Bramet';

  return str(get(order, 'Producent')) || '';
};

const producerAliases = {
  eurodoor: ['eurodoor', 'drzwi'],
  ekookna: ['ekookna', 'eko okna', 'eko-okna', 'okna', 'okno'],
  medos: ['medos', 'parapet', 'parapety'],
  fill: ['fill', 'roleta', 'rolety', 'zaluzja', 'zaluzje', 'moskitiera', 'moskitiery'],
  bramet: ['bramet', 'wisniowski', 'wiśniowski', 'brama', 'bramy']
};

const normalizeProducer = (v) => {
  const p = norm(v);

  if (p.includes('eurodoor') || p.includes('drzwi')) return 'eurodoor';
  if (p.includes('eko okna') || p.includes('ekookna') || p.includes('okno') || p.includes('okna')) return 'ekookna';
  if (p.includes('medos') || p.includes('parapet')) return 'medos';
  if (p.includes('fill') || p.includes('rolet') || p.includes('zaluz') || p.includes('moskit')) return 'fill';
  if (p.includes('bramet') || p.includes('wisniowski') || p.includes('bram')) return 'bramet';

  return p;
};

const producentRaw = input.producent || detectProducer();
const producentKey = normalizeProducer(producentRaw);

if (!producentKey) {
  return [{
    json: {
      success: false,
      error: 'Nie rozpoznano producenta. Podaj producenta ręcznie.'
    }
  }];
}

const aliases = producerAliases[producentKey] || [producentKey];

const contractor = contractors.find(c => {
  const active = norm(get(c, 'Aktywny'));

  const searchText = norm([
    get(c, 'Nazwa'),
    get(c, 'Producent'),
    get(c, 'Produkt / kategoria'),
    get(c, 'Kategoria'),
    get(c, 'Typ produktu'),
    get(c, 'Opis'),
    get(c, 'Email zamówienia'),
    get(c, 'Email zamowienia'),
    get(c, 'Email'),
    get(c, 'Email opiekuna')
  ].join(' '));

  return (
    active !== 'nie' &&
    aliases.some(alias => searchText.includes(norm(alias)))
  );
});

if (!contractor) {
  return [{
    json: {
      success: false,
      error: `Nie znaleziono kontrahenta dla producenta: ${producentRaw}`,
      producent: producentRaw,
      producent_key: producentKey,
      aliases
    }
  }];
}

const to =
  str(get(contractor, 'Email zamówienia')) ||
  str(get(contractor, 'Email zamowienia')) ||
  str(get(contractor, 'Email')) ||
  str(get(contractor, 'Email opiekuna'));

if (!to) {
  return [{
    json: {
      success: false,
      error: `Brak emaila zamówień dla producenta: ${producentRaw}`,
      kontrahent: get(contractor, 'Nazwa')
    }
  }];
}

const producent = str(get(contractor, 'Nazwa')) || producentRaw;

const klient = `${str(get(order, 'Imię'))} ${str(get(order, 'Nazwisko'))}`.trim();

const modele = splitMulti(get(order, 'Model'));
const kolory = splitMulti(get(order, 'Kolor'));
const wymiary = splitMulti(get(order, 'Wymiary'));
const jednostki = splitMulti(get(order, 'Jednostka (mm/cm/m)') || get(order, 'Jednostka'));
const ilosci = splitMulti(get(order, 'Ilość'));
const kierunki = splitMulti(get(order, 'Kierunek otwierania ') || get(order, 'Kierunek otwierania'));
const produkty = splitMulti(get(order, 'Produkty (opis)') || get(order, 'Produkt'));

const maxLen = Math.max(
  modele.length,
  kolory.length,
  wymiary.length,
  jednostki.length,
  ilosci.length,
  kierunki.length,
  produkty.length,
  1
);

while (modele.length < maxLen && modele.length > 0) modele.push(modele[modele.length - 1]);
while (kolory.length < maxLen && kolory.length > 0) kolory.push(kolory[kolory.length - 1]);
while (wymiary.length < maxLen && wymiary.length > 0) wymiary.push(wymiary[wymiary.length - 1]);
while (jednostki.length < maxLen && jednostki.length > 0) jednostki.push(jednostki[jednostki.length - 1]);
while (ilosci.length < maxLen && ilosci.length > 0) ilosci.push(ilosci[ilosci.length - 1]);
while (kierunki.length < maxLen && kierunki.length > 0) kierunki.push(kierunki[kierunki.length - 1]);
while (produkty.length < maxLen && produkty.length > 0) produkty.push(produkty[produkty.length - 1]);

const productLines = [];

for (let i = 0; i < maxLen; i++) {
  productLines.push([
    `Pozycja ${i + 1}:`,
    produkty[i] ? `Produkt: ${produkty[i]}` : '',
    modele[i] ? `Model: ${modele[i]}` : '',
    kolory[i] ? `Kolor: ${kolory[i]}` : '',
    wymiary[i] ? `Wymiar: ${wymiary[i]}` : '',
    jednostki[i] ? `Jednostka: ${jednostki[i]}` : '',
    ilosci[i] ? `Ilość: ${ilosci[i]}` : '',
    kierunki[i] ? `Kierunek otwierania: ${kierunki[i]}` : ''
  ].filter(Boolean).join('\n'));
}

const address = [
  str(get(order, 'Ulica')),
  str(get(order, 'Kod pocztowy')),
  str(get(order, 'Miasto'))
].filter(Boolean).join(', ');

const subject = `Zamówienie — ${klient}`;

const body =
`Dzień dobry,

chciałbym złożyć zamówienie:

${productLines.join('\n\n')}

Pozdrawiam,
Company-ABC`;

return [{
  json: {
    success: true,
    row_number: order.row_number,
    to,
    subject,
    body,
    producent,
    producent_raw: producentRaw,
    producent_key: producentKey,
    kontrahent: get(contractor, 'Nazwa'),
    klient
  }
}];

const mail = $('Code — klasyfikacja do drafta').first().json;
const rules = $input.all().map(i => i.json);

const norm = (v) =>
  String(v || '')
    .toLowerCase()
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .replace(/[_\-–—/]+/g, ' ')
    .replace(/\s+/g, ' ')
    .trim();

const canonicalType = (v) => {
  const x = norm(v);

  if (x.includes('klient') && x.includes('wycena')) return 'klient wycena';
  if (x.includes('reklamacja')) return 'reklamacja';
  if (x.includes('kontrahent') && x.includes('odpowiedz')) return 'kontrahent odpowiedz';
  if (x.includes('kontrahent')) return 'kontrahent odpowiedz';
  if (x.includes('newsletter')) return 'newsletter';
  if (x.includes('web') || x.includes('kosztorys')) return 'web kosztorys';

  return x;
};

const get = (row, wantedName) => {
  const wanted = norm(wantedName);
  const key = Object.keys(row).find(k => norm(k) === wanted);
  return key ? row[key] : '';
};

const isYes = (v) => {
  const x = norm(v);
  return x === 'tak' || x === 'yes' || x === 'true' || x === '1';
};

const replaceVars = (template) =>
  String(template || '')
    .replaceAll('{{subject}}', mail.mail_subject || '')
    .replaceAll('{{from}}', mail.mail_from_email || '')
    .replaceAll('{{typ_maila}}', mail.typ_maila || '');

const mailType = canonicalType(mail.typ_maila);
const activeRules = rules.filter(r => isYes(get(r, 'Aktywne')));

const matchingRules = activeRules.filter(r => {
  const ruleType = canonicalType(get(r, 'Typ maila'));

  if (ruleType !== mailType) return false;

  const warunkiRaw = String(get(r, 'Warunki') || '').trim();
  if (!warunkiRaw) return true;

  const keywords = warunkiRaw
    .split(',')
    .map(x => norm(x))
    .filter(Boolean);

  if (!keywords.length) return true;

  const allText = norm(`${mail.mail_subject} ${mail.mail_from_raw} ${mail.mail_text}`);
  const words = allText.split(' ').filter(Boolean);

  return keywords.some(k => {
    if (allText.includes(k)) return true;

    return words.some(w => {
      return w.includes(k) || k.includes(w);
    });
  });
});

const rule = matchingRules[0];

if (!rule) {
  return [{
    json: {
      ...mail,
      create_draft: 'NIE',
      reason: `Brak aktywnej reguły w arkuszu dla typu: ${mail.typ_maila}`,
      debug_mail_type: mailType,
      debug_rules_types: activeRules.map(r => canonicalType(get(r, 'Typ maila'))).join(' | '),
      debug_rules_count: rules.length,
      debug_active_count: activeRules.length,
      debug_columns_first_rule: rules[0] ? Object.keys(rules[0]).join(' | ') : ''
    }
  }];
}

const createDraft = isYes(get(rule, 'Twórz draft')) ? 'TAK' : 'NIE';

const draftSubject = replaceVars(get(rule, 'Temat') || 'Re: {{subject}}');
const draftBody = replaceVars(get(rule, 'Odpowiedź'));

if (createDraft !== 'TAK' || !draftBody.trim()) {
  return [{
    json: {
      ...mail,
      create_draft: 'NIE',
      matched_rule: get(rule, 'Typ maila'),
      reason: createDraft !== 'TAK'
        ? 'Reguła znaleziona, ale Twórz draft != TAK'
        : 'Reguła znaleziona, ale Odpowiedź jest pusta'
    }
  }];
}

return [{
  json: {
    ...mail,
    create_draft: 'TAK',
    matched_rule: get(rule, 'Typ maila'),
    draft_to: mail.mail_from_email,
    draft_subject: draftSubject,
    draft_body: draftBody,
    thread_id: mail.thread_id
  }
}];
